import {
  Controller,
  Get,
  HttpException,
  HttpStatus,
  Inject,
} from '@nestjs/common';
import { PrismaService } from './database/prisma.service';
import { MinioStorageAdapter } from './modules/storage/infrastructure/minio-storage.adapter';
import { Public } from './modules/auth/interface/public.decorator';

export interface HealthResponse {
  status: 'ok' | 'degraded';
  postgres: 'up' | 'down';
  minio: 'up' | 'down';
}

@Controller()
export class AppController {
  constructor(
    private readonly prisma: PrismaService,
    private readonly storage: MinioStorageAdapter,
  ) {}

  @Public()
  @Get('health')
  async health(): Promise<HealthResponse> {
    const [pgUp, minioUp] = await Promise.all([
      this.checkPostgres(),
      this.storage.ping(),
    ]);

    const status = pgUp && minioUp ? 'ok' : 'degraded';
    const body: HealthResponse = {
      status,
      postgres: pgUp ? 'up' : 'down',
      minio: minioUp ? 'up' : 'down',
    };

    if (status === 'degraded') {
      throw new HttpException(body, HttpStatus.SERVICE_UNAVAILABLE);
    }

    return body;
  }

  private async checkPostgres(): Promise<boolean> {
    try {
      await this.prisma.$queryRaw`SELECT 1`;
      return true;
    } catch {
      return false;
    }
  }
}

/**
 * PR2 Integration Tests ÔÇö Schema + Seed assertions
 *
 * Strict TDD: this file is written BEFORE the migration and seed exist.
 * Tests MUST fail initially, then pass after T2.5ÔÇôT2.9.
 *
 * Runs against futuragest_test DB (backend/.env.test loaded by globalSetup).
 */

import { createPrismaClient } from './prisma-client';

// DATABASE_URL is set to futuragest_test by the Jest globalSetup (loads .env.test)
const prisma = createPrismaClient();

beforeAll(async () => {
  await prisma.$connect();
});

afterAll(async () => {
  await prisma.$disconnect();
});

describe('Seed ÔÇö authoritative counts', () => {
  it('produces exactly 2 zones', async () => {
    const count = await prisma.zone.count();
    expect(count).toBe(2);
  });

  it('produces exactly 13 municipios', async () => {
    const count = await prisma.municipio.count();
    expect(count).toBe(13);
  });

  it('produces exactly 23 supervisors', async () => {
    const count = await prisma.supervisor.count();
    expect(count).toBe(23);
  });

  it('produces exactly 1 SYSTEM_ADMIN user', async () => {
    const count = await prisma.user.count({ where: { role: 'SYSTEM_ADMIN' } });
    expect(count).toBe(1);
  });

  it('SYSTEM_ADMIN has mustChangePassword = true', async () => {
    const admin = await prisma.user.findFirst({ where: { role: 'SYSTEM_ADMIN' } });
    expect(admin).not.toBeNull();
    expect(admin!.mustChangePassword).toBe(true);
  });

  it('SYSTEM_ADMIN email is admin@futuragest.co', async () => {
    const admin = await prisma.user.findFirst({ where: { role: 'SYSTEM_ADMIN' } });
    expect(admin!.email).toBe('admin@futuragest.co');
  });
});

