  });

  it('Zona Bajo Cauca has exactly 7 supervisors (Caucasia 3, Taraz├í 1, Nech├¡ 1, Zaragoza 1, C├íceres 1)', async () => {
    const zone = await prisma.zone.findUnique({ where: { name: 'Zona Bajo Cauca' } });
