describe('Schema constraints', () => {
  it('Municipio names are unique within a zone (@@unique([zoneId, name]))', async () => {
    // If seed ran twice (idempotency), there should be no duplicates
    const municipios = await prisma.municipio.findMany();
    const pairs = municipios.map((m) => `${m.zoneId}:${m.name}`);
    const unique = new Set(pairs);
    expect(pairs.length).toBe(unique.size);
  });

  it('no active duplicate assignment possible: each operario has at most one open assignment', async () => {
    // Active assignments: endDate IS NULL
    const activeAssignments = await prisma.assignment.findMany({
      where: { endDate: null },
    });
    const operarioIds = activeAssignments.map((a) => a.operarioId);
    const uniqueIds = new Set(operarioIds);
    // Every operario id should appear at most once among active assignments
    expect(operarioIds.length).toBe(uniqueIds.size);
  });

  it('Supervisor has a denormalized zoneId that matches their municipio zone', async () => {
    const supervisors = await prisma.supervisor.findMany({ take: 5 });
    for (const sup of supervisors) {
      expect(sup.zoneId).toBeTruthy();
    }
  });
});

/**
 * T-15 RED ÔåÆ T-16 GREEN: CheckInAttendanceUseCase unit spec.
 * Covers AT-01 (happy path), AT-02 (body isolation), AT-04 (clientRef idempotency),
 * AT-05 (operario not in scope ÔåÆ 404), AT-07/AT-08 (GPS validation).
 * PR-3: OP-51 (inactive operario ÔåÆ InactiveOperarioError), OP-52 (active ÔåÆ proceeds normally).
 *
 * WARNING-3 fix: execute() now returns { record, created } so the controller
 * can distinguish 201 (new row) from 200 (idempotent hit).
 */

import { CheckInAttendanceUseCase } from './check-in-attendance.use-case';
import {
  AttendanceAlreadyExistsError,
  InactiveOperarioError,
  InvalidGpsError,
  OperarioNotInScopeError,
} from '../domain/attendance.errors';
import type { AttendanceRepositoryPort } from '../domain/ports/attendance-repository.port';
import type { Attendance } from '@prisma/client';

// ÔöÇÔöÇ Mock factory helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

function makeAttendance(overrides: Partial<Attendance> = {}): Attendance {
  return {
    id: 'ATT-1',
    supervisorId: 'S1',
    operarioId: 'O1',
    zoneId: 'Z1',
    date: '2026-05-31',
    checkInCapturedAt: new Date('2026-05-31T08:00:00Z'),
    checkInReceivedAt: new Date('2026-05-31T08:00:01Z'),
    checkInLat: 7.5,
    checkInLng: -76.5,
    checkInAccuracy: 10,
    checkOutCapturedAt: null,
    checkOutReceivedAt: null,
    checkOutLat: null,
    checkOutLng: null,
    checkOutAccuracy: null,
    checkInVerification: null,
    checkOutVerification: null,
    signatureKey: null,
    checkOutSignatureKey: null,
    clientRef: 'REF-A',
    checkOutClientRef: null,
    completedAt: null,
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makeMockRepo(overrides: Partial<AttendanceRepositoryPort> = {}): AttendanceRepositoryPort {
  return {
    create: jest.fn(),
    findById: jest.fn(),
    findMany: jest.fn(),
    findByClientRef: jest.fn().mockResolvedValue(null),
    findByCheckOutClientRef: jest.fn().mockResolvedValue(null),
    findByOperarioAndDate: jest.fn().mockResolvedValue(null),
    update: jest.fn(),
    ...overrides,
  };
}

function makeMockOperarioRepo() {
  return {
    findById: jest.fn().mockResolvedValue({ id: 'O1', supervisorId: 'S1' }),
  };
}

function makeMockStatusPort(isActive: boolean | null = true) {
  return { isActive: jest.fn().mockResolvedValue(isActive) };
}

function makeMockHolder(
  ctx: { supervisorId: string; zoneId: string; role: string } = {
    supervisorId: 'S1',
    zoneId: 'Z1',
    role: 'SUPERVISOR',
  },
) {
  return { current: jest.fn().mockReturnValue(ctx) };
}

const VALID_INPUT = {
  operarioId: 'O1',
  date: '2026-05-31',
  checkInCapturedAt: '2026-05-31T08:00:00Z',
  checkInLat: 7.5,
  checkInLng: -76.5,
  checkInAccuracy: 10,
  clientRef: 'REF-A',
};

// ÔöÇÔöÇ Tests ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

describe('CheckInAttendanceUseCase', () => {
  describe('AT-01 ÔÇö happy path: creates attendance record', () => {
    it('calls repo.create with supervisorId/zoneId from scope holder (not body); returns created=true', async () => {
      const attendance = makeAttendance();
      const repo = makeMockRepo({ create: jest.fn().mockResolvedValue(attendance) });
      const operarioRepo = makeMockOperarioRepo();
      const holder = makeMockHolder();
      const statusPort = makeMockStatusPort(true); // active

      const useCase = new CheckInAttendanceUseCase(repo, operarioRepo as any, holder as any, statusPort as any);
      const result = await useCase.execute(VALID_INPUT);

      expect(result.record).toBe(attendance);
      expect(result.created).toBe(true);
      expect(repo.create).toHaveBeenCalledTimes(1);
      const createCall = (repo.create as jest.Mock).mock.calls[0][0];
      expect(createCall.supervisorId).toBe('S1');
      expect(createCall.zoneId).toBe('Z1');
      expect(createCall.operarioId).toBe('O1');
      // Server-generated timestamp (not from input)
      expect(createCall.checkInReceivedAt).toBeInstanceOf(Date);
    });
  });

  describe('AT-04 ÔÇö clientRef idempotency: returns existing record without creating', () => {
    it('returns created=false when clientRef already exists (pre-create path)', async () => {
      const existing = makeAttendance({ clientRef: 'REF-A' });
      const repo = makeMockRepo({
        findByClientRef: jest.fn().mockResolvedValue(existing),
        create: jest.fn(),
      });
      const holder = makeMockHolder();
      const operarioRepo = makeMockOperarioRepo();
      const statusPort = makeMockStatusPort(true);

      const useCase = new CheckInAttendanceUseCase(repo, operarioRepo as any, holder as any, statusPort as any);
      const result = await useCase.execute(VALID_INPUT);

      expect(result.record).toBe(existing);
      expect(result.created).toBe(false);
      expect(repo.create).not.toHaveBeenCalled();
    });

    it('returns created=false on P2002 clientRef race (post-create idempotency fallback)', async () => {
      const existing = makeAttendance({ clientRef: 'REF-A' });
      const p2002 = Object.assign(new Error('Unique constraint failed'), {
        code: 'P2002',
        meta: { target: ['clientRef'] },
      });
      const repo = makeMockRepo({
        findByClientRef: jest.fn()
          .mockResolvedValueOnce(null)       // first check: not found
          .mockResolvedValueOnce(existing),  // after race: found
        create: jest.fn().mockRejectedValue(p2002),
      });
      const operarioRepo = makeMockOperarioRepo();
      const holder = makeMockHolder();
      const statusPort = makeMockStatusPort(true);

      const useCase = new CheckInAttendanceUseCase(repo, operarioRepo as any, holder as any, statusPort as any);
      const result = await useCase.execute(VALID_INPUT);

      expect(result.record).toBe(existing);
      expect(result.created).toBe(false);
    });
  });

  describe('AT-03 ÔÇö duplicate operario+date with different clientRef ÔåÆ 409', () => {
    it('throws AttendanceAlreadyExistsError on P2002 unique violation for operarioId+date', async () => {
      const p2002Error = Object.assign(new Error('Unique constraint failed'), {
        code: 'P2002',
        meta: { target: ['operarioId', 'date'] },
      });
      const repo = makeMockRepo({
        findByClientRef: jest.fn().mockResolvedValue(null),
        create: jest.fn().mockRejectedValue(p2002Error),
      });
      const operarioRepo = makeMockOperarioRepo();
      const holder = makeMockHolder();
      const statusPort = makeMockStatusPort(true);

      const useCase = new CheckInAttendanceUseCase(repo, operarioRepo as any, holder as any, statusPort as any);

      await expect(useCase.execute({ ...VALID_INPUT, clientRef: 'REF-B' })).rejects.toThrow(
        AttendanceAlreadyExistsError,
      );
      expect(repo.create).toHaveBeenCalledTimes(1);
    });
  });

  describe('AT-07 ÔÇö GPS lat out of range ÔåÆ InvalidGpsError', () => {
    it('throws InvalidGpsError for lat > 90 without calling repo.create', async () => {
      const repo = makeMockRepo();
      const operarioRepo = makeMockOperarioRepo();
      const holder = makeMockHolder();
      const statusPort = makeMockStatusPort(true);

      const useCase = new CheckInAttendanceUseCase(repo, operarioRepo as any, holder as any, statusPort as any);

      await expect(
        useCase.execute({ ...VALID_INPUT, checkInLat: 999 }),
      ).rejects.toThrow(InvalidGpsError);
      expect(repo.create).not.toHaveBeenCalled();
    });
  });

  describe('AT-08 ÔÇö GPS lng out of range ÔåÆ InvalidGpsError', () => {
    it('throws InvalidGpsError for lng > 180', async () => {
      const repo = makeMockRepo();
      const operarioRepo = makeMockOperarioRepo();
      const holder = makeMockHolder();
      const statusPort = makeMockStatusPort(true);

      const useCase = new CheckInAttendanceUseCase(repo, operarioRepo as any, holder as any, statusPort as any);

      await expect(
        useCase.execute({ ...VALID_INPUT, checkInLng: 200 }),
      ).rejects.toThrow(InvalidGpsError);
      expect(repo.create).not.toHaveBeenCalled();
    });
  });

  describe('AT-05 ÔÇö operario not in supervisor scope ÔåÆ 404', () => {
    it('throws OperarioNotInScopeError when operario belongs to a different supervisor', async () => {
      const repo = makeMockRepo();
      // findById returns operario with different supervisorId
      const operarioRepo = {
        findById: jest.fn().mockResolvedValue(null), // scoped repo returns null = not in scope
      };
      const holder = makeMockHolder();
      const statusPort = makeMockStatusPort(true);

      const useCase = new CheckInAttendanceUseCase(repo, operarioRepo as any, holder as any, statusPort as any);

      await expect(useCase.execute(VALID_INPUT)).rejects.toThrow(OperarioNotInScopeError);
      expect(repo.create).not.toHaveBeenCalled();
    });
  });

  // ÔöÇÔöÇ PR-3: OP-51, OP-52 ÔÇö Inactive operario guard ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  describe('OP-51 ÔÇö inactive operario ÔåÆ InactiveOperarioError', () => {
    it('throws InactiveOperarioError when isActive returns false; AttendanceRepo.create NOT called', async () => {
      const repo = makeMockRepo({ create: jest.fn() });
      const operarioRepo = makeMockOperarioRepo(); // findById returns operario (in scope)
      const holder = makeMockHolder();
      const statusPort = makeMockStatusPort(false); // inactive

      const useCase = new CheckInAttendanceUseCase(repo, operarioRepo as any, holder as any, statusPort as any);

      await expect(useCase.execute(VALID_INPUT)).rejects.toThrow(InactiveOperarioError);
      expect(repo.create).not.toHaveBeenCalled();
    });
  });

  describe('OP-52 ÔÇö active operario ÔåÆ proceeds normally (regression)', () => {
    it('does NOT throw InactiveOperarioError; AttendanceRepo.create IS called', async () => {
      const attendance = makeAttendance();
      const repo = makeMockRepo({ create: jest.fn().mockResolvedValue(attendance) });
      const operarioRepo = makeMockOperarioRepo();
      const holder = makeMockHolder();
      const statusPort = makeMockStatusPort(true); // active

      const useCase = new CheckInAttendanceUseCase(repo, operarioRepo as any, holder as any, statusPort as any);

      const result = await useCase.execute(VALID_INPUT);

      expect(result.record).toBe(attendance);
      expect(result.created).toBe(true);
      expect(repo.create).toHaveBeenCalledTimes(1);
    });
  });

  // ÔöÇÔöÇ VM-01..VM-03 ÔÇö VerificationMethod (checkInVerification) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  describe('VM-01 ÔÇö checkIn with verification ÔåÆ persists checkInVerification', () => {
    it('passes checkInVerification: BIOMETRIC to repo.create when provided', async () => {
      const attendance = makeAttendance();
      const repo = makeMockRepo({ create: jest.fn().mockResolvedValue(attendance) });
      const operarioRepo = makeMockOperarioRepo();
      const holder = makeMockHolder();
      const statusPort = makeMockStatusPort(true);

      const useCase = new CheckInAttendanceUseCase(repo, operarioRepo as any, holder as any, statusPort as any);
      await useCase.execute({ ...VALID_INPUT, verification: 'BIOMETRIC' });

      const createCall = (repo.create as jest.Mock).mock.calls[0][0];
      expect(createCall.checkInVerification).toBe('BIOMETRIC');
    });

    it('passes checkInVerification: DEVICE_CREDENTIAL when provided', async () => {
      const attendance = makeAttendance();
      const repo = makeMockRepo({ create: jest.fn().mockResolvedValue(attendance) });
      const operarioRepo = makeMockOperarioRepo();
      const holder = makeMockHolder();
      const statusPort = makeMockStatusPort(true);

      const useCase = new CheckInAttendanceUseCase(repo, operarioRepo as any, holder as any, statusPort as any);
      await useCase.execute({ ...VALID_INPUT, verification: 'DEVICE_CREDENTIAL' });

      const createCall = (repo.create as jest.Mock).mock.calls[0][0];
      expect(createCall.checkInVerification).toBe('DEVICE_CREDENTIAL');
    });
  });

  describe('VM-02 ÔÇö checkIn without verification ÔåÆ persists null', () => {
    it('passes checkInVerification: null to repo.create when verification is absent', async () => {
      const attendance = makeAttendance();
      const repo = makeMockRepo({ create: jest.fn().mockResolvedValue(attendance) });
      const operarioRepo = makeMockOperarioRepo();
      const holder = makeMockHolder();
      const statusPort = makeMockStatusPort(true);

      const useCase = new CheckInAttendanceUseCase(repo, operarioRepo as any, holder as any, statusPort as any);
      // VALID_INPUT has no verification field
      await useCase.execute(VALID_INPUT);

      const createCall = (repo.create as jest.Mock).mock.calls[0][0];
      expect(createCall.checkInVerification).toBeNull();
    });
  });
});

/**
 * CheckInAttendanceUseCase ÔÇö creates a new attendance record for check-in.
 *
 * AT-01: happy path ÔÇö creates record with supervisorId/zoneId from JWT scope.
 * AT-02: supervisorId/zoneId in body are IGNORED ÔÇö only scope holder is used.
 * AT-04: clientRef idempotency ÔÇö duplicate clientRef ÔåÆ return existing record (HTTP 200).
 * AT-05: operario not in supervisor scope ÔåÆ OperarioNotInScopeError (404).
 * AT-07/AT-08: GPS validation ÔåÆ InvalidGpsError (400).
 * AT-03: same operario+date, different clientRef ÔåÆ AttendanceAlreadyExistsError (409).
 *
 * Sequence:
 * 1. Validate GPS ranges (fail fast before any DB access).
 * 2. If clientRef provided: findByClientRef ÔåÆ if found, return existing (idempotent).
 * 3. Verify operario belongs to this supervisor (scoped lookup ÔåÆ null = not in scope).
 * 4. Create; catch P2002:
 *    - target includes 'clientRef' ÔåÆ race-condition idempotency: re-fetch and return existing.
 *    - target includes 'operarioId'/'date' ÔåÆ DuplicateAttendanceError (409).
 */

import type { Attendance, VerificationMethod } from '@prisma/client';
import type { AttendanceRepositoryPort } from '../domain/ports/attendance-repository.port';
import type { ScopeContextHolder } from '../../auth/domain/scope-context';
import type { OperarioStatusPort } from '../../iam/domain/ports/operario-status.port';
import {
  AttendanceAlreadyExistsError,
  AttendanceDateMismatchError,
  InactiveOperarioError,
  InvalidGpsError,
  OperarioNotInScopeError,
} from '../domain/attendance.errors';
import { toBogotaDate } from '../domain/bogota-date';

export interface CheckInInput {
  operarioId: string;
  date: string;
  checkInCapturedAt: string; // ISO 8601 from client
  checkInLat: number;
  checkInLng: number;
  checkInAccuracy?: number;
  clientRef: string;
  /**
   * Audit label: how the supervisor verified identity before check-in.
   * Comes from the client ÔÇö AUDIT LABEL ONLY. No authorization logic may depend on this.
   */
  verification?: VerificationMethod;
}

// Minimal interface for the scoped operario repo (avoids importing the full class)
interface ScopedOperarioRepo {
  findById(id: string): Promise<{ id: string; supervisorId: string } | null>;
}

function validateGps(lat: number, lng: number, accuracy?: number): void {
  if (lat < -90 || lat > 90) {
    throw new InvalidGpsError('lat', lat);
  }
  if (lng < -180 || lng > 180) {
    throw new InvalidGpsError('lng', lng);
  }
  if (accuracy !== undefined && accuracy !== null && accuracy < 0) {
    throw new InvalidGpsError('accuracy', accuracy);
  }
}

function isPrismaUniqueError(err: unknown): boolean {
  return (
    typeof err === 'object' &&
    err !== null &&
    'code' in err &&
    (err as { code: unknown }).code === 'P2002'
  );
}

function getConstraintTarget(err: unknown): string[] {
  if (
    typeof err === 'object' &&
    err !== null &&
    'meta' in err &&
    typeof (err as any).meta === 'object' &&
    (err as any).meta !== null &&
    'target' in (err as any).meta
  ) {
    const target = (err as any).meta.target;
    return Array.isArray(target) ? target : [target];
  }
  return [];
}

export interface CheckInResult {
  record: Attendance;
  /** true when a new row was inserted; false on clientRef idempotent hit (both pre-create and race). */
  created: boolean;
}

export class CheckInAttendanceUseCase {
  constructor(
    private readonly attendanceRepo: AttendanceRepositoryPort,
    private readonly operarioRepo: ScopedOperarioRepo,
    private readonly scopeHolder: ScopeContextHolder,
    private readonly operarioStatus: OperarioStatusPort,
  ) {}

  async execute(input: CheckInInput): Promise<CheckInResult> {
    // 1. GPS validation (fail fast)
    validateGps(input.checkInLat, input.checkInLng, input.checkInAccuracy);

    // 2. clientRef idempotency: if already exists, return without creating (created=false).
    //    This early return MUST precede Fix 8's date guard ÔÇö offline sync replays may arrive
    //    with stale date values that would mismatch against today's server-derived date.
    const existing = await this.attendanceRepo.findByClientRef(input.clientRef);
    if (existing) {
      return { record: existing, created: false };
    }

    // 2b. Fix 8 ÔÇö server-side date derivation (single point of truth).
    //     Colombia is UTC-5, no DST. Derive the authoritative Bogot├í local date from
    //     checkInCapturedAt; validate the client-provided date matches it.
    //     Only fires for NEW records (not idempotent replays, which returned above).
    const checkInDate = new Date(input.checkInCapturedAt);
    const serverDate = toBogotaDate(checkInDate);
    if (input.date !== serverDate) {
      throw new AttendanceDateMismatchError(input.date, serverDate);
    }

    // 3. Operario ownership check via scoped repo (fail-closed: null = not in scope)
    const operario = await this.operarioRepo.findById(input.operarioId);
    if (!operario) {
      throw new OperarioNotInScopeError(input.operarioId);
    }

    // 3b. Inactive guard ÔÇö check AFTER ownership (OP-33, REQ-09)
    // isActive === false ÔåÆ operario is deactivated ÔåÆ 409
    // isActive === null  ÔåÆ not found (already handled above by OperarioNotInScopeError)
    // isActive === true  ÔåÆ active, proceed normally
    const active = await this.operarioStatus.isActive(input.operarioId);
    if (active === false) {
      throw new InactiveOperarioError(input.operarioId);
    }

    // supervisorId and zoneId come EXCLUSIVELY from the verified JWT scope
    const ctx = this.scopeHolder.current();
    const supervisorId = ctx.supervisorId!;
    const zoneId = ctx.zoneId!;

    // 4. Create ÔÇö catch P2002 for both idempotency race and duplicate (operarioId, date).
    //    Use serverDate (server-derived Bogot├í local date) ÔÇö NOT input.date ÔÇö as the
    //    single point of truth (Fix 8). They are guaranteed equal here by the guard above,
    //    but using serverDate makes the intent explicit and survives future refactors.
    try {
      const record = await this.attendanceRepo.create({
        supervisorId,
        operarioId: input.operarioId,
        zoneId,
        date: serverDate,
        checkInCapturedAt: new Date(input.checkInCapturedAt),
        checkInReceivedAt: new Date(),
        checkInLat: input.checkInLat,
        checkInLng: input.checkInLng,
        checkInAccuracy: input.checkInAccuracy ?? null,
        // Audit label only ÔÇö no authorization logic may depend on checkInVerification.
        checkInVerification: input.verification ?? null,
        clientRef: input.clientRef,
        signatureKey: null,
        completedAt: null,
      });
      return { record, created: true };
    } catch (err) {
      if (isPrismaUniqueError(err)) {
        const target = getConstraintTarget(err);
        // Race on clientRef ÔåÆ idempotency: re-fetch and return existing (created=false)
        if (target.includes('clientRef') || target.join(',').includes('clientRef')) {
          const idempotent = await this.attendanceRepo.findByClientRef(input.clientRef);
          if (idempotent) return { record: idempotent, created: false };
        }
        // Duplicate (operarioId, date) ÔÇö fetch the conflicting record to carry in the error
        const conflicting = await this.attendanceRepo.findByOperarioAndDate(
          input.operarioId,
          input.date,
        );
        throw new AttendanceAlreadyExistsError(
          input.operarioId,
          input.date,
          conflicting ?? ({ id: 'unknown', operarioId: input.operarioId, date: input.date } as any),
        );
      }
      throw err;
    }
  }
}

/**
 * Fix 8 ÔÇö Server-side date derivation in CheckInAttendanceUseCase (RED ÔåÆ GREEN).
 *
 * Covers:
 *   F8-1  ÔÇö check-in with date that mismatches capturedAt ÔåÆ AttendanceDateMismatchError
 *   F8-2  ÔÇö check-in with consistent date+capturedAt ÔåÆ persists the server-derived date
 *   F8-3  ÔÇö check-in near Bogot├í midnight (04:30Z = 23:30 local prev day) with client date
 *            = previous day ÔåÆ succeeds and stores previous day
 *   F8-4  ÔÇö idempotent replay (existing clientRef) ÔåÆ no date validation, returns existing record
 */

import { CheckInAttendanceUseCase } from './check-in-attendance.use-case';
import { AttendanceDateMismatchError } from '../domain/attendance.errors';
import type { AttendanceRepositoryPort } from '../domain/ports/attendance-repository.port';
import type { Attendance } from '@prisma/client';

// ÔöÇÔöÇÔöÇ Mock factories ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

