    supervisorId: 'S1',
    operarioId: 'O1',
    zoneId: 'Z1',
    date: '2026-06-09',
    checkInCapturedAt: new Date('2026-06-09T13:00:00Z'),
    checkInReceivedAt: new Date('2026-06-09T13:00:01Z'),
