    checkOutSignatureKey: null,
    clientRef: 'REF-A',
    checkOutClientRef: null,
    completedAt: null,
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makeMockRepo(overrides: Partial<AttendanceRepositoryPort> = {}): AttendanceRepositoryPort {
  return {
    create: jest.fn(),
    findById: jest.fn(),
    findMany: jest.fn(),
    findByClientRef: jest.fn().mockResolvedValue(null),
    findByCheckOutClientRef: jest.fn().mockResolvedValue(null),
    findByOperarioAndDate: jest.fn().mockResolvedValue(null),
    update: jest.fn(),
    ...overrides,
  };
}

function makeMockOperarioRepo() {
  return {
    findById: jest.fn().mockResolvedValue({ id: 'O1', supervisorId: 'S1' }),
  };
}

function makeMockStatusPort(isActive: boolean | null = true) {
  return { isActive: jest.fn().mockResolvedValue(isActive) };
}

function makeMockHolder(
  ctx: { supervisorId: string; zoneId: string; role: string } = {
    supervisorId: 'S1',
    zoneId: 'Z1',
    role: 'SUPERVISOR',
  },
) {
  return { current: jest.fn().mockReturnValue(ctx) };
}

function makeUseCase(repoOverrides: Partial<AttendanceRepositoryPort> = {}) {
  const repo = makeMockRepo(repoOverrides);
  const operarioRepo = makeMockOperarioRepo();
  const holder = makeMockHolder();
  const statusPort = makeMockStatusPort(true);
  const useCase = new CheckInAttendanceUseCase(
    repo,
    operarioRepo as any,
    holder as any,
    statusPort as any,
  );
  return { useCase, repo, operarioRepo, holder, statusPort };
}

// ÔöÇÔöÇÔöÇ Tests ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

describe('CheckInAttendanceUseCase ÔÇö server-side date derivation (Fix 8)', () => {

  describe('F8-1 ÔÇö mismatched date vs capturedAt ÔåÆ AttendanceDateMismatchError', () => {
    it('throws when client sends date=2026-06-09 but capturedAt=2026-06-10T13:00Z (Bogot├í = 2026-06-10)', async () => {
      const { useCase } = makeUseCase();

      await expect(
        useCase.execute({
          operarioId: 'O1',
          date: '2026-06-09',
          checkInCapturedAt: '2026-06-10T13:00:00Z', // Bogot├í = 2026-06-10
          checkInLat: 7.5,
          checkInLng: -76.5,
          clientRef: 'REF-MISMATCH',
        }),
      ).rejects.toThrow(AttendanceDateMismatchError);
    });

    it('throws when client sends date=2026-06-10 but capturedAt is on 2026-06-09 (bogota)', async () => {
      const { useCase } = makeUseCase();

      await expect(
        useCase.execute({
          operarioId: 'O1',
          date: '2026-06-10', // wrong: capturedAt is 13:00Z = 08:00 Bogot├í = still 2026-06-09
          checkInCapturedAt: '2026-06-09T13:00:00Z',
          checkInLat: 7.5,
          checkInLng: -76.5,
          clientRef: 'REF-MISMATCH2',
        }),
      ).rejects.toThrow(AttendanceDateMismatchError);
    });
  });

  describe('F8-2 ÔÇö consistent date+capturedAt ÔåÆ persists the server-derived date', () => {
    it('creates record when date and capturedAt agree on Bogot├í local day', async () => {
      const att = makeAttendance({ date: '2026-06-09' });
      const { useCase, repo } = makeUseCase({ create: jest.fn().mockResolvedValue(att) });

      const result = await useCase.execute({
        operarioId: 'O1',
        date: '2026-06-09',
        checkInCapturedAt: '2026-06-09T13:00:00Z', // Bogot├í = 2026-06-09T08:00
        checkInLat: 7.5,
        checkInLng: -76.5,
        clientRef: 'REF-A',
      });

      expect(result.created).toBe(true);
      expect(repo.create).toHaveBeenCalledTimes(1);
      const createArg = (repo.create as jest.Mock).mock.calls[0][0];
      // The server-derived date (not raw client date) is what gets persisted
      expect(createArg.date).toBe('2026-06-09');
    });
  });

  describe('F8-3 ÔÇö near Bogot├í midnight: capturedAt=04:30Z = 23:30 local prev day', () => {
    it('succeeds and stores previous day when client date matches server-derived date', async () => {
      // 2026-06-02T04:30Z = 2026-06-01T23:30 Bogot├í ÔåÆ server-derived date = "2026-06-01"
      const att = makeAttendance({ date: '2026-06-01' });
      const { useCase, repo } = makeUseCase({ create: jest.fn().mockResolvedValue(att) });

      const result = await useCase.execute({
        operarioId: 'O1',
        date: '2026-06-01', // client sends correct previous-day date
        checkInCapturedAt: '2026-06-02T04:30:00Z', // Bogot├í = 2026-06-01T23:30
        checkInLat: 7.5,
        checkInLng: -76.5,
        clientRef: 'REF-MIDNIGHT',
      });

      expect(result.created).toBe(true);
      const createArg = (repo.create as jest.Mock).mock.calls[0][0];
      // Server-derived date = "2026-06-01"
      expect(createArg.date).toBe('2026-06-01');
    });

    it('throws AttendanceDateMismatchError when client sends wrong date near midnight', async () => {
      const { useCase } = makeUseCase();

      // capturedAt = 04:30Z = Bogot├í 23:30 prev day ÔåÆ server derives "2026-06-01"
      // client mistakenly sends "2026-06-02" (current UTC date, not Bogot├í date)
      await expect(
        useCase.execute({
          operarioId: 'O1',
          date: '2026-06-02', // wrong
          checkInCapturedAt: '2026-06-02T04:30:00Z',
          checkInLat: 7.5,
          checkInLng: -76.5,
          clientRef: 'REF-MIDNIGHT-WRONG',
        }),
      ).rejects.toThrow(AttendanceDateMismatchError);
    });
  });

  describe('F8-4 ÔÇö idempotent replay via clientRef ÔåÆ no date mismatch guard', () => {
    it('returns existing record immediately without running date validation', async () => {
      const existingAtt = makeAttendance({ clientRef: 'REF-IDEMPOTENT', date: '2026-01-01' });
      const repo = makeMockRepo({ findByClientRef: jest.fn().mockResolvedValue(existingAtt) });
      const operarioRepo = makeMockOperarioRepo();
      const holder = makeMockHolder();
      const statusPort = makeMockStatusPort(true);
      const useCase = new CheckInAttendanceUseCase(
        repo, operarioRepo as any, holder as any, statusPort as any,
      );

      // date = '2026-06-09' but capturedAt is for '2026-01-01' ÔÇö would mismatch
      // BUT clientRef already exists ÔåÆ idempotent path returns immediately
      const result = await useCase.execute({
        operarioId: 'O1',
        date: '2099-01-01', // wildly different date
        checkInCapturedAt: '2026-06-09T13:00:00Z',
        checkInLat: 7.5,
        checkInLng: -76.5,
        clientRef: 'REF-IDEMPOTENT',
      });

      expect(result.record).toBe(existingAtt);
      expect(result.created).toBe(false);
      expect(repo.create).not.toHaveBeenCalled();
    });
  });
});

