    tokenC2 = mintToken({ sub: c2UserId, role: 'COORDINADOR', zoneId: zoneZ2Id });
    tokenAdmin = mintToken({ sub: adminUserId, role: 'SYSTEM_ADMIN' });
    tokenCoord = tokenC1;
  }, 60_000);

  afterAll(async () => {
