  /**
   * Derive the Colombia/Bogot├í local date (UTC-5, no DST) from a UTC instant.
   * Used to keep checkIn fixtures consistent with Fix 8's server-side date guard.
   */
  function toBogotaDate(instant: Date): string {
    return new Date(instant.getTime() - 5 * 3600 * 1000).toISOString().slice(0, 10);
  }

  /**
   * Build a capturedAt ISO string that falls on the given YYYY-MM-DD in Bogot├í time.
   * Uses midday (12:00) Bogot├í = 17:00 UTC to stay well clear of midnight boundaries.
   */
  function capturedAtForDate(bogotaDate: string): string {
    return `${bogotaDate}T17:00:00Z`;
  }

  // Helper to create attendance via check-in (returns supertest Test, not a Promise).
  // Fix 8: date and checkInCapturedAt must be consistent (server derives date from capturedAt).
  // When a specific date is provided, capturedAt is set to midday on that date (Bogot├í time).
  // When no date is provided, today's Bogot├í date is derived from the capturedAt.
  function checkIn(opts: {
    token: string;
    operarioId?: string;
    date?: string;
    lat?: number;
    lng?: number;
    clientRef?: string;
    extraBody?: Record<string, unknown>;
  }) {
    const now = new Date();
    const capturedAt = opts.date ? capturedAtForDate(opts.date) : now.toISOString();
    const date = opts.date ?? toBogotaDate(now);
    return request(app.getHttpServer())
      .post('/asistencia/check-in')
      .set('Authorization', `Bearer ${opts.token}`)
      .send({
        operarioId: opts.operarioId ?? o1Id,
        date,
        checkInCapturedAt: capturedAt,
        checkInLat: opts.lat ?? 7.5,
        checkInLng: opts.lng ?? -76.5,
        clientRef: opts.clientRef ?? `test-ref-${Date.now()}-${Math.random()}`,
        ...(opts.extraBody ?? {}),
      });
  }

