    it('SI-22 ÔÇö by-clientRef + checkOutClientRef idempotency compose: replay ÔåÆ 200 same record', async () => {
      const checkInClientRef = `si22-cin-${Date.now()}`;
      const { id } = await createAttendanceWithSig({
