/**
 * RED ÔåÆ GREEN tests for Fix 7 ÔÇö close persists real supervisor zoneId.
 *
 * Current bug: CloseCompensationPeriodUseCase resolves zoneId via
 * `operario['zoneId'] ?? ''` but zoneId is NOT a field on Operario ÔÇö
 * it lives on the supervisor. Every snapshot persists zoneId='',
 * breaking COORDINADOR scope filtering.
 *
 * Fix: close use-case resolves the supervisor's zoneId via a SEPARATE query
 * (W4 rule: no scoped-relation includes). If supervisor lookup fails ÔåÆ throws
 * (fail loudly ÔÇö no '' default).
 *
 * Covers:
 *   F7-1  ÔÇö close persists the supervisor's real zoneId (not '')
 *   F7-2  ÔÇö supervisor lookup returns null ÔåÆ throws ZoneIdResolutionError (no '' default)
 *   F7-3  ÔÇö supervisorId is missing on operario ÔåÆ throws ZoneIdResolutionError
 */

import { Decimal } from '@prisma/client/runtime/client';
import { CloseCompensationPeriodUseCase } from './close-compensation-period.use-case';
import { ZoneIdResolutionError } from '../domain/compensacion.errors';
import type { CompensationPeriodRepositoryPort } from '../domain/ports/compensation-period-repository.port';

/** Minimal in-memory supervisor zone resolver port. */
interface SupervisorZoneReaderPort {
  findZoneIdBySupervisorId(supervisorId: string): Promise<string | null>;
}

/** Helper: build a minimal Operario-like object (supervisorId field, no zoneId field). */
function makeOperario(supervisorId: string): { id: string; supervisorId: string } {
  return { id: 'op-1', supervisorId };
}

/** Helper: make a minimal CompensationPeriodRepositoryPort stub. */
function makePeriodRepo(
  existing: null | { periodKey: string; clientRef: string | null } = null,
): CompensationPeriodRepositoryPort {
  const createMock = jest.fn().mockImplementation((data) =>
    Promise.resolve({
      id: 'cp-new',
      ...data,
      closedAt: new Date(),
      createdAt: new Date(),
      updatedAt: new Date(),
      decidedAt: data.decidedAt ?? null,
      paidAt: null,
      payoutRef: null,
      divergedAt: null,
    }),
  );
  return {
    findByOperarioAndPeriod: jest.fn().mockResolvedValue(existing),
    findPreviousClosed: jest.fn().mockResolvedValue(null),
    findByClientRef: jest.fn().mockResolvedValue(null),
    findOverlappingClosed: jest.fn().mockResolvedValue(null),
    create: createMock,
    markPaid: jest.fn().mockResolvedValue(1),
    markDiverged: jest.fn().mockResolvedValue(undefined),
    findClosedContainingDate: jest.fn().mockResolvedValue(null),
  };
}

function makeAttendanceReader() {
  return { findCompletedInRange: jest.fn().mockResolvedValue([]) };
}

function makePolicyRepo() {
  return {
    findTimeline: jest.fn().mockResolvedValue([
      {
        id: 'pol-1',
        horasDiarias: new Decimal('8'),
        vigenteDesde: new Date('2026-01-01T00:00:00Z'),
        createdAt: new Date(),
      },
    ]),
    create: jest.fn(),
    findLatestBefore: jest.fn(),
  };
}

function makeCalcUseCase() {
  return {
    execute: jest.fn().mockResolvedValue({
      creditos: new Decimal('0'),
      debitos: new Decimal('0'),
      carryIn: new Decimal('0'),
      saldo: new Decimal('0'),
      perDay: [],
    }),
  };
}

describe('CloseCompensationPeriodUseCase ÔÇö zoneId resolution (Fix 7)', () => {
  const DESDE = '2026-06-01';
  const HASTA = '2026-06-15';

  beforeEach(() => jest.clearAllMocks());

  // ÔöÇÔöÇ F7-1: real zoneId persisted ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('F7-1 ÔÇö persists the supervisor real zoneId (not empty string)', async () => {
    const periodRepo = makePeriodRepo();
    const operarioReader = {
      findById: jest.fn().mockResolvedValue(makeOperario('sup-1')),
    };
    const supervisorZoneReader: SupervisorZoneReaderPort = {
      findZoneIdBySupervisorId: jest.fn().mockResolvedValue('zone-urab├í'),
    };

    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader() as any,
      makePolicyRepo() as any,
      makeCalcUseCase() as any,
      operarioReader as any,
      supervisorZoneReader as any,
    );

    await useCase.execute({
      operarioId: 'op-1',
      desde: DESDE,
      hasta: HASTA,
      disposition: null,
      approvedByUserId: 'hr-user',
      clientRef: null,
    });

    const createCall = (periodRepo.create as jest.Mock).mock.calls[0][0];
    expect(createCall.zoneId).toBe('zone-urab├í');
    expect(createCall.zoneId).not.toBe('');
  });

  // ÔöÇÔöÇ F7-2: supervisor lookup returns null ÔåÆ throws, no '' fallback ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('F7-2 ÔÇö supervisor zoneId lookup returns null ÔåÆ throws ZoneIdResolutionError', async () => {
    const periodRepo = makePeriodRepo();
    const operarioReader = {
      findById: jest.fn().mockResolvedValue(makeOperario('sup-1')),
    };
    const supervisorZoneReader: SupervisorZoneReaderPort = {
      findZoneIdBySupervisorId: jest.fn().mockResolvedValue(null),
    };

    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader() as any,
      makePolicyRepo() as any,
      makeCalcUseCase() as any,
      operarioReader as any,
      supervisorZoneReader as any,
    );

    await expect(
      useCase.execute({
        operarioId: 'op-1',
        desde: DESDE,
        hasta: HASTA,
        disposition: null,
        approvedByUserId: 'hr-user',
        clientRef: null,
      }),
    ).rejects.toBeInstanceOf(ZoneIdResolutionError);

    // Verify create was NOT called (abort before write)
    expect(periodRepo.create).not.toHaveBeenCalled();
  });

  // ÔöÇÔöÇ F7-3: supervisorId missing on operario ÔåÆ throws ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('F7-3 ÔÇö operario without supervisorId ÔåÆ throws ZoneIdResolutionError', async () => {
    const periodRepo = makePeriodRepo();
    const operarioReader = {
      // operario has no supervisorId field
      findById: jest.fn().mockResolvedValue({ id: 'op-1' }),
    };
    const supervisorZoneReader: SupervisorZoneReaderPort = {
      findZoneIdBySupervisorId: jest.fn(),
    };

    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader() as any,
      makePolicyRepo() as any,
      makeCalcUseCase() as any,
      operarioReader as any,
      supervisorZoneReader as any,
    );

    await expect(
      useCase.execute({
        operarioId: 'op-1',
        desde: DESDE,
        hasta: HASTA,
        disposition: null,
        approvedByUserId: 'hr-user',
        clientRef: null,
      }),
    ).rejects.toBeInstanceOf(ZoneIdResolutionError);

    expect(supervisorZoneReader.findZoneIdBySupervisorId).not.toHaveBeenCalled();
  });
});

/**
 * B6.1 RED ÔÇö CloseCompensationPeriodUseCase unit spec.
 *
 * EP-04a  ÔÇö happy path: first close ÔåÆ snapshot written with correct fields.
 * EP-04b  ÔÇö idempotency: same clientRef ÔåÆ return existing, no second write.
 * EP-04c  ÔÇö different ref (real double-close) ÔåÆ CompensationPeriodAlreadyClosedError (409).
 * EP-04d  ÔÇö negative saldo + no disposition ÔåÆ DispositionRequiredError (422).
 * EP-04e  ÔÇö scoped operario not found ÔåÆ OperarioNotInScopeError (404).
 *
 * Mirrors check-out-attendance pattern (completedAt lock + clientRef replay).
 * CalculatePeriodBalanceUseCase is pure ÔÇö injected directly with no mocking.
 */

import { Decimal } from '@prisma/client/runtime/client';
import { CloseCompensationPeriodUseCase } from './close-compensation-period.use-case';
import { CalculatePeriodBalanceUseCase } from './calculate-period-balance.use-case';
import {
  CompensationPeriodAlreadyClosedError,
  DispositionRequiredError,
  NonCanonicalPeriodRangeError,
  NonContiguousCloseError,
  ClientRefConflictError,
} from '../domain/compensacion.errors';
import { OperarioNotInScopeError } from '../../asistencia/domain/attendance.errors';
import type { AttendanceReaderPort, AttendanceReaderRecord } from '../domain/ports/attendance-reader.port';
import type { JornadaPolicyRepositoryPort, JornadaPolicyRecord } from '../domain/ports/jornada-policy-repository.port';
import type { OperarioReaderPort } from '../domain/ports/operario-reader.port';
import type {
  CompensationPeriodRepositoryPort,
  CompensationPeriodRecord,
} from '../domain/ports/compensation-period-repository.port';

// ÔöÇÔöÇÔöÇ Helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

function makePolicy(dateStr: string, hours: number): JornadaPolicyRecord {
  return {
    id: `pol-${dateStr}`,
    horasDiarias: new Decimal(hours),
    vigenteDesde: new Date(`${dateStr}T00:00:00Z`),
    createdAt: new Date(),
  };
}

function makeAttendance(date: string, durationHours: number): AttendanceReaderRecord {
  const checkIn = new Date(`${date}T07:00:00Z`);
  const checkOut = new Date(checkIn.getTime() + durationHours * 3600_000);
  return {
    id: `att-${date}`,
    operarioId: 'O1',
    date,
    checkInCapturedAt: checkIn,
    checkOutCapturedAt: checkOut,
    completedAt: checkOut,
  };
}

function makePeriodRecord(overrides: Partial<CompensationPeriodRecord> = {}): CompensationPeriodRecord {
  return {
    id: 'cp-1',
    operarioId: 'O1',
    zoneId: 'zone-1',
    supervisorId: 'sup-1',
    periodKey: '2026-05-Q1',
    desde: '2026-05-01',
    hasta: '2026-05-15',
    creditos: new Decimal('0.50'),
    debitos: new Decimal('1.00'),
    carryIn: new Decimal('0.00'),
    saldo: new Decimal('-0.50'),
    disposition: 'CARRY_OVER',
    approvedByUserId: 'user-1',
    decidedAt: new Date(),
    closedAt: new Date(),
    clientRef: 'ref-abc',
    paidAt: null,
    payoutRef: null,
    divergedAt: null,
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makeAttendanceReader(records: AttendanceReaderRecord[]): jest.Mocked<AttendanceReaderPort> {
  return { findCompletedInRange: jest.fn().mockResolvedValue(records) };
}

function makePolicyRepo(policies: JornadaPolicyRecord[]): jest.Mocked<JornadaPolicyRepositoryPort> {
  return {
    create: jest.fn(),
    findTimeline: jest.fn().mockResolvedValue(policies),
    findLatestBefore: jest.fn(),
  };
}

function makeOperarioReader(operario: { id: string; supervisorId?: string; zoneId?: string } | null): jest.Mocked<OperarioReaderPort> {
  return { findById: jest.fn().mockResolvedValue(operario) };
}

function makePeriodRepo(existingPeriod: CompensationPeriodRecord | null = null): jest.Mocked<CompensationPeriodRepositoryPort> {
  return {
    findByOperarioAndPeriod: jest.fn().mockResolvedValue(existingPeriod),
    findPreviousClosed: jest.fn().mockResolvedValue(null),
    findByClientRef: jest.fn().mockResolvedValue(null),
    findOverlappingClosed: jest.fn().mockResolvedValue(null),
    create: jest.fn().mockResolvedValue(makePeriodRecord()),
    markPaid: jest.fn().mockResolvedValue(1),
    markDiverged: jest.fn().mockResolvedValue(undefined),
    findClosedContainingDate: jest.fn().mockResolvedValue(null),
  };
}

/** Fix 7: supervisor zone reader mock ÔÇö returns zone-1 for sup-1, null otherwise. */
const makeSupervisorZoneReader = (zoneId: string = 'zone-1') => ({
  findZoneIdBySupervisorId: jest.fn().mockResolvedValue(zoneId),
});

// ÔöÇÔöÇÔöÇ Tests ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

describe('CloseCompensationPeriodUseCase', () => {
  const calcUseCase = new CalculatePeriodBalanceUseCase();
  const baseOperario = { id: 'O1', supervisorId: 'sup-1' }; // no zoneId ÔÇö resolved via supervisor query
  const basePolicy = makePolicy('2026-01-01', 8);
  const baseAttendances = [
    makeAttendance('2026-05-01', 7.5), // +0 extra or -0.5 under
    makeAttendance('2026-05-02', 8.5), // +0.5 credit
  ];

  // ÔöÇÔöÇ EP-04a ÔÇö Happy path: first close ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('EP-04a ÔÇö first close: snapshot written with correct fields', async () => {
    const periodRepo = makePeriodRepo(null); // no existing period
    const operarioReader = makeOperarioReader(baseOperario);
    const attendanceReader = makeAttendanceReader(baseAttendances);
    const policyRepo = makePolicyRepo([basePolicy]);

    const created = makePeriodRecord({
      disposition: 'CARRY_OVER',
      approvedByUserId: 'admin-user',
      clientRef: 'ref-new',
    });
    periodRepo.create.mockResolvedValue(created);

    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      attendanceReader,
      policyRepo,
      calcUseCase,
      operarioReader,
      makeSupervisorZoneReader() as any,
    );

    const result = await useCase.execute({
      operarioId: 'O1',
      desde: '2026-05-01',
      hasta: '2026-05-15',
      disposition: 'CARRY_OVER',
      approvedByUserId: 'admin-user',
      clientRef: 'ref-new',
    });

    expect(result.idempotent).toBe(false);
    expect(result.period.disposition).toBe('CARRY_OVER');
    expect(result.period.approvedByUserId).toBe('admin-user');
    expect(periodRepo.create).toHaveBeenCalledTimes(1);

    // Verify create was called with correct structure
    const createArg = (periodRepo.create as jest.Mock).mock.calls[0][0];
    expect(createArg.operarioId).toBe('O1');
    expect(createArg.disposition).toBe('CARRY_OVER');
    expect(createArg.approvedByUserId).toBe('admin-user');
    expect(createArg.clientRef).toBe('ref-new');
  });

  // ÔöÇÔöÇ EP-04b ÔÇö Idempotency: same clientRef ÔåÆ return existing, no write ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('EP-04b ÔÇö idempotent replay: same clientRef ÔåÆ returns existing period, no second create', async () => {
    const existing = makePeriodRecord({ clientRef: 'ref-existing' });
    const periodRepo = makePeriodRepo(existing);

    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader(baseAttendances),
      makePolicyRepo([basePolicy]),
      calcUseCase,
      makeOperarioReader(baseOperario),
      makeSupervisorZoneReader() as any,
    );

    const result = await useCase.execute({
      operarioId: 'O1',
      desde: '2026-05-01',
      hasta: '2026-05-15',
      disposition: 'CARRY_OVER',
      approvedByUserId: 'admin-user',
      clientRef: 'ref-existing', // same as stored ÔåÆ idempotent
    });

    expect(result.idempotent).toBe(true);
    expect(result.period.id).toBe('cp-1');
    // No write should have occurred
    expect(periodRepo.create).not.toHaveBeenCalled();
  });

  // ÔöÇÔöÇ EP-04c ÔÇö Different ref ÔåÆ CompensationPeriodAlreadyClosedError (409) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('EP-04c ÔÇö different clientRef on already-closed period ÔåÆ CompensationPeriodAlreadyClosedError', async () => {
    const existing = makePeriodRecord({ clientRef: 'ref-original' });
    const periodRepo = makePeriodRepo(existing);

    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader(baseAttendances),
      makePolicyRepo([basePolicy]),
      calcUseCase,
      makeOperarioReader(baseOperario),
      makeSupervisorZoneReader() as any,
    );

    await expect(
      useCase.execute({
        operarioId: 'O1',
        desde: '2026-05-01',
        hasta: '2026-05-15',
        disposition: 'PAYROLL_DEDUCTION',
        approvedByUserId: 'admin-user',
        clientRef: 'ref-different', // different ÔåÆ conflict
      }),
    ).rejects.toThrow(CompensationPeriodAlreadyClosedError);

    expect(periodRepo.create).not.toHaveBeenCalled();
  });

  // ÔöÇÔöÇ EP-04c variant ÔÇö absent clientRef on already-closed period ÔåÆ 409 ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('EP-04c-variant ÔÇö absent clientRef on already-closed period ÔåÆ CompensationPeriodAlreadyClosedError', async () => {
    const existing = makePeriodRecord({ clientRef: 'ref-original' });
    const periodRepo = makePeriodRepo(existing);

    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader(baseAttendances),
      makePolicyRepo([basePolicy]),
      calcUseCase,
      makeOperarioReader(baseOperario),
      makeSupervisorZoneReader() as any,
    );

    await expect(
      useCase.execute({
        operarioId: 'O1',
        desde: '2026-05-01',
        hasta: '2026-05-15',
        disposition: 'CARRY_OVER',
        approvedByUserId: 'admin-user',
        // no clientRef ÔÇö cannot replay
      }),
    ).rejects.toThrow(CompensationPeriodAlreadyClosedError);
  });

  // ÔöÇÔöÇ EP-04d ÔÇö Negative saldo, no disposition ÔåÆ DispositionRequiredError (422) ÔöÇ

  it('EP-04d ÔÇö negative saldo + no disposition ÔåÆ DispositionRequiredError', async () => {
    // 7h vs 8h policy ÔåÆ saldo = -1h (negative)
    const shortAttendance = [makeAttendance('2026-05-01', 7)];
    const periodRepo = makePeriodRepo(null);

    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader(shortAttendance),
      makePolicyRepo([basePolicy]),
      calcUseCase,
      makeOperarioReader(baseOperario),
      makeSupervisorZoneReader() as any,
    );

    await expect(
      useCase.execute({
        operarioId: 'O1',
        desde: '2026-05-01',
        hasta: '2026-05-15',
        // no disposition ÔÇö required when saldo < 0
        approvedByUserId: 'admin-user',
        clientRef: 'ref-neg',
      }),
    ).rejects.toThrow(DispositionRequiredError);

    expect(periodRepo.create).not.toHaveBeenCalled();
  });

  // ÔöÇÔöÇ EP-04e ÔÇö Scoped operario not found ÔåÆ OperarioNotInScopeError (404) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('EP-04e ÔÇö operario not in scope ÔåÆ OperarioNotInScopeError (fail-closed)', async () => {
    const periodRepo = makePeriodRepo(null);

    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader([]),
      makePolicyRepo([basePolicy]),
      calcUseCase,
      makeOperarioReader(null), // null = out of scope,
      makeSupervisorZoneReader() as any,
    );

    await expect(
      useCase.execute({
        operarioId: 'OUT-OF-SCOPE',
        desde: '2026-05-01',
        hasta: '2026-05-15',
        disposition: 'CARRY_OVER',
        approvedByUserId: 'admin-user',
        clientRef: 'ref-oos',
      }),
    ).rejects.toThrow(OperarioNotInScopeError);

    // No DB write should occur
    expect(periodRepo.create).not.toHaveBeenCalled();
  });

  // ÔöÇÔöÇ Fix 2: canonical fortnight validation ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('Fix2-a ÔÇö hasta beyond Q1 fortnight ÔåÆ NonCanonicalPeriodRangeError (422)', async () => {
    const periodRepo = makePeriodRepo(null);
    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader(baseAttendances),
      makePolicyRepo([basePolicy]),
      calcUseCase,
      makeOperarioReader(baseOperario),
      makeSupervisorZoneReader() as any,
    );

    await expect(
      useCase.execute({
        operarioId: 'O1',
        desde: '2026-05-01',
        hasta: '2026-05-31', // beyond Q1 canonical hasta=15
        disposition: 'CARRY_OVER',
        approvedByUserId: 'admin-user',
      }),
    ).rejects.toThrow(NonCanonicalPeriodRangeError);
    expect(periodRepo.create).not.toHaveBeenCalled();
  });

  it('Fix2-b ÔÇö desde not on day 1 or 16 ÔåÆ NonCanonicalPeriodRangeError (422)', async () => {
    const periodRepo = makePeriodRepo(null);
    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader(baseAttendances),
      makePolicyRepo([basePolicy]),
      calcUseCase,
      makeOperarioReader(baseOperario),
      makeSupervisorZoneReader() as any,
    );

    await expect(
      useCase.execute({
        operarioId: 'O1',
        desde: '2026-05-05', // not day 1 or 16
        hasta: '2026-05-15',
        disposition: 'CARRY_OVER',
        approvedByUserId: 'admin-user',
      }),
    ).rejects.toThrow(NonCanonicalPeriodRangeError);
  });

  it('Fix2-c ÔÇö canonical Q1 range passes validation (2026-05-01 to 2026-05-15)', async () => {
    const periodRepo = makePeriodRepo(null);
    const created = makePeriodRecord({ disposition: null, saldo: new Decimal('1.00') });
    periodRepo.create.mockResolvedValue(created);
    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader([makeAttendance('2026-05-01', 9)]),
      makePolicyRepo([basePolicy]),
      calcUseCase,
      makeOperarioReader(baseOperario),
      makeSupervisorZoneReader() as any,
    );

    const result = await useCase.execute({
      operarioId: 'O1',
      desde: '2026-05-01',
      hasta: '2026-05-15',
      approvedByUserId: 'admin-user',
    });
    expect(result.idempotent).toBe(false);
  });

  it('Fix2-d ÔÇö canonical Q2 range passes validation (2026-05-16 to 2026-05-31)', async () => {
    const periodRepo = makePeriodRepo(null);
    const created = makePeriodRecord({
      periodKey: '2026-05-Q2',
      desde: '2026-05-16',
      hasta: '2026-05-31',
      disposition: null,
      saldo: new Decimal('1.00'),
    });
    periodRepo.create.mockResolvedValue(created);
    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader([makeAttendance('2026-05-16', 9)]),
      makePolicyRepo([basePolicy]),
      calcUseCase,
      makeOperarioReader(baseOperario),
      makeSupervisorZoneReader() as any,
    );

    const result = await useCase.execute({
      operarioId: 'O1',
      desde: '2026-05-16',
      hasta: '2026-05-31',
      approvedByUserId: 'admin-user',
    });
    expect(result.idempotent).toBe(false);
  });

  // ÔöÇÔöÇ Fix 3: exact-prevKey carryIn ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('Fix3-a ÔÇö Q1 closed CARRY_OVER saldo=-2, closing Q2 ÔåÆ carryIn = -2', async () => {
    const prevQ1 = makePeriodRecord({
      periodKey: '2026-05-Q1',
      disposition: 'CARRY_OVER',
      saldo: new Decimal('-2.00'),
      carryIn: new Decimal('0'),
    });
    const periodRepo = makePeriodRepo(null);
    // findByOperarioAndPeriod: no existing Q2; findPreviousClosed returns Q1
    periodRepo.findPreviousClosed.mockResolvedValue(prevQ1);
    // Also wire exact-key lookup: Fix3 requires exact match on prevKey
    periodRepo.findByOperarioAndPeriod
      .mockImplementation((_oid: string, key: string) =>
        Promise.resolve(key === '2026-05-Q1' ? prevQ1 : null),
      );

    const created = makePeriodRecord({
      periodKey: '2026-05-Q2',
      desde: '2026-05-16',
      hasta: '2026-05-31',
      carryIn: new Decimal('-2.00'),
      saldo: new Decimal('-2.00'),
      disposition: 'CARRY_OVER',
    });
    periodRepo.create.mockResolvedValue(created);

    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader([]),
      makePolicyRepo([basePolicy]),
      calcUseCase,
      makeOperarioReader(baseOperario),
      makeSupervisorZoneReader() as any,
    );

    const result = await useCase.execute({
      operarioId: 'O1',
      desde: '2026-05-16',
      hasta: '2026-05-31',
      disposition: 'CARRY_OVER',
      approvedByUserId: 'admin-user',
    });

    expect(result.idempotent).toBe(false);
    const createArg = (periodRepo.create as jest.Mock).mock.calls[0][0];
    expect(createArg.carryIn.toNumber()).toBe(-2);
  });

  it('Fix3-b ÔÇö Q1 closed CARRY_OVER saldo=-2, Q2 NOT closed, closing Q3 ÔåÆ NonContiguousCloseError (409)', async () => {
    const prevQ1 = makePeriodRecord({
      periodKey: '2026-05-Q1',
      disposition: 'CARRY_OVER',
      saldo: new Decimal('-2.00'),
    });

    const periodRepo = makePeriodRepo(null);
    // No Q2 period (gap)
    periodRepo.findByOperarioAndPeriod.mockResolvedValue(null);
    // findPreviousClosed (gap-debt check) returns Q1 which has debt and is NOT the immediate predecessor of Q3
    periodRepo.findPreviousClosed.mockResolvedValue(prevQ1);

    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader([]),
      makePolicyRepo([basePolicy]),
      calcUseCase,
      makeOperarioReader(baseOperario),
      makeSupervisorZoneReader() as any,
    );

    // Closing Q2-of-June (Q1 of June's prev = Q2 of May; Q2 of May's prev = Q1 of May)
    // Simulate: closing 2026-06-Q1, prevKey = 2026-05-Q2 (gap), most-recent = Q1 CARRY_OVER
    await expect(
      useCase.execute({
        operarioId: 'O1',
        desde: '2026-06-01',
        hasta: '2026-06-15',
        disposition: 'CARRY_OVER',
        approvedByUserId: 'admin-user',
      }),
    ).rejects.toThrow(NonContiguousCloseError);
    expect(periodRepo.create).not.toHaveBeenCalled();
  });

  it('Fix3-c ÔÇö gap period has no debt (saldo >= 0), closing Q3 ÔåÆ no throw, carryIn = 0', async () => {
    const prevQ1NoDept = makePeriodRecord({
      periodKey: '2026-05-Q1',
      disposition: null,
      saldo: new Decimal('1.00'), // positive ÔÇö no debt
    });

    const periodRepo = makePeriodRepo(null);
    periodRepo.findByOperarioAndPeriod.mockResolvedValue(null);
    periodRepo.findPreviousClosed.mockResolvedValue(prevQ1NoDept);

    const created = makePeriodRecord({
      periodKey: '2026-06-Q1',
      desde: '2026-06-01',
      hasta: '2026-06-15',
      carryIn: new Decimal('0'),
      saldo: new Decimal('1.00'),
      disposition: null,
    });
    periodRepo.create.mockResolvedValue(created);

    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader([makeAttendance('2026-06-01', 9)]),
      makePolicyRepo([basePolicy]),
      calcUseCase,
      makeOperarioReader(baseOperario),
      makeSupervisorZoneReader() as any,
    );

    const result = await useCase.execute({
      operarioId: 'O1',
      desde: '2026-06-01',
      hasta: '2026-06-15',
      approvedByUserId: 'admin-user',
    });
    expect(result.idempotent).toBe(false);
    const createArg = (periodRepo.create as jest.Mock).mock.calls[0][0];
    expect(createArg.carryIn.toNumber()).toBe(0);
  });

  it('Fix3-d ÔÇö month-boundary prevKey: June Q1 ÔåÆ May Q2 (exact key lookup)', async () => {
    const mayQ2 = makePeriodRecord({
      periodKey: '2026-05-Q2',
      desde: '2026-05-16',
      hasta: '2026-05-31',
      disposition: 'CARRY_OVER',
      saldo: new Decimal('-1.50'),
      carryIn: new Decimal('0'),
    });

    const periodRepo = makePeriodRepo(null);
    periodRepo.findByOperarioAndPeriod
      .mockImplementation((_oid: string, key: string) =>
        Promise.resolve(key === '2026-05-Q2' ? mayQ2 : null),
      );
    periodRepo.findPreviousClosed.mockResolvedValue(mayQ2);

    const created = makePeriodRecord({
      periodKey: '2026-06-Q1',
      desde: '2026-06-01',
      hasta: '2026-06-15',
      carryIn: new Decimal('-1.50'),
      saldo: new Decimal('-1.50'),
      disposition: 'CARRY_OVER',
    });
    periodRepo.create.mockResolvedValue(created);

    const useCase = new CloseCompensationPeriodUseCase(
      periodRepo,
      makeAttendanceReader([]),
      makePolicyRepo([basePolicy]),
      calcUseCase,
      makeOperarioReader(baseOperario),
      makeSupervisorZoneReader() as any,
    );

    const result = await useCase.execute({
      operarioId: 'O1',
      desde: '2026-06-01',
      hasta: '2026-06-15',
      disposition: 'CARRY_OVER',
      approvedByUserId: 'admin-user',
    });
    expect(result.idempotent).toBe(false);
    const createArg = (periodRepo.create as jest.Mock).mock.calls[0][0];
