interface FakePrisma {
  user: {
    create: jest.Mock;
    findUnique: jest.Mock;
    updateMany: jest.Mock;
    update: jest.Mock;
  };
  $transaction: jest.Mock;
}

function makePrisma(overrides: Partial<FakePrisma> = {}): FakePrisma {
  const prisma: FakePrisma = {
    user: {
