/**
 * PrismaOrgRepository ÔÇö infrastructure adapter implementing OrgRepositoryPort.
 *
 * Responsibilities:
 * - createManagementUser: persists new management-role user with mustChangePassword=true.
 * - assignCoordinador: validates zone + user + role, then executes a $transaction
 *   with clear-then-set ordering to preserve the @unique coordinatedZoneId constraint (INV-05).
 * - findZones / findMunicipios: delegates to ScopedZoneRepository / ScopedMunicipioRepository
 *   (scope filtering is already applied by those repos via applyScopeFilter).
 * - createZone / updateZone / deleteZone: zone CRUD with uniqueness + referential guards.
 * - createMunicipio / updateMunicipio / deleteMunicipio: municipio CRUD with guards.
 *
 * Error mapping:
 * - Prisma P2002 (unique violation on user.email) ÔåÆ EmailInUseError.
 * - Prisma P2002 on zone.name ÔåÆ ZoneNameInUseError.
 * - Prisma P2002 on (municipio.zoneId, municipio.name) ÔåÆ MunicipioNameInUseError.
 * - zoneRepo.findById returns null ÔåÆ ZoneNotFoundError.
 * - prisma.zone.findUnique returns null ÔåÆ ZoneNotFoundError.
 * - prisma.municipio.findUnique returns null ÔåÆ MunicipioNotFoundError.
 * - user.findUnique returns null ÔåÆ UserNotFoundError.
 * - user.role !== COORDINADOR ÔåÆ InvalidCoordinadorRoleError.
 * - zone children count > 0 ÔåÆ ZoneHasDependentsError.
 * - municipio supervisor count > 0 ÔåÆ MunicipioHasDependentsError.
 */

import { Injectable } from '@nestjs/common';
import type { Zone, Municipio } from '@prisma/client';
import { PrismaService } from '../../../database/prisma.service';
import type {
  OrgRepositoryPort,
  CreateManagementUserParams,
  AssignCoordinadorParams,
  UserListItem,
} from '../domain/ports/org-repository.port';
import {
  EmailInUseError,
  ZoneNotFoundError,
  ZoneNameInUseError,
  ZoneHasDependentsError,
  UserNotFoundError,
  InvalidCoordinadorRoleError,
  MunicipioNotFoundError,
  MunicipioNameInUseError,
  MunicipioHasDependentsError,
} from '../domain/org.errors';
import type { ScopedZoneRepository } from './scoped-zone.repository';
import type { ScopedMunicipioRepository } from './scoped-municipio.repository';

@Injectable()
export class PrismaOrgRepository implements OrgRepositoryPort {
  constructor(
    private readonly prisma: PrismaService,
    private readonly zoneRepo: ScopedZoneRepository,
    private readonly municipioRepo: ScopedMunicipioRepository,
  ) {}

  // ÔöÇÔöÇÔöÇ createManagementUser ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async createManagementUser(params: CreateManagementUserParams): Promise<{ id: string }> {
    try {
      const user = await this.prisma.user.create({
        data: {
          email: params.email,
          passwordHash: params.passwordHash,
          role: params.role,
          mustChangePassword: true,
          // coordinatedZoneId intentionally omitted ÔÇö Prisma default is null.
          // Management roles (GERENCIA, TALENTO_HUMANO, LIDER_OPERATIVO) are GLOBAL_ROLES.
        },
        select: { id: true },
      });

      return { id: user.id };
    } catch (err) {
      // Prisma unique constraint violation on User.email
      if (this.isPrismaUniqueError(err)) {
        throw new EmailInUseError(params.email);
      }
      throw err;
    }
  }

  // ÔöÇÔöÇÔöÇ assignCoordinador ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async assignCoordinador(params: AssignCoordinadorParams): Promise<void> {
    const { userId, zoneId } = params;

    // 1. Validate zone exists (pre-transaction ÔÇö fast guard, no @unique risk here)
    const zone = await this.zoneRepo.findById(zoneId);
    if (!zone) {
      throw new ZoneNotFoundError(zoneId);
    }

    // 2. Validate user exists and has COORDINADOR role
    const user = await this.prisma.user.findUnique({ where: { id: userId } });
    if (!user) {
      throw new UserNotFoundError(userId);
    }
    if (user.role !== 'COORDINADOR') {
      throw new InvalidCoordinadorRoleError(user.role);
    }

    // 3. Transactional clear-then-set (INV-05 ÔÇö preserves @unique coordinatedZoneId)
    //    Step A: release current holder of target zone (if any)
    //    Step B: assign target user to the zone
    //    This ordering is MANDATORY: set-before-clear would transiently violate @unique.
    await this.prisma.$transaction(async (tx) => {
      // Step A: clear coordinatedZoneId on any user currently holding this zone
      await (tx as any).user.updateMany({
        where: { coordinatedZoneId: zoneId },
        data: { coordinatedZoneId: null },
      });

      // Step B: set coordinatedZoneId on the target user
      // This also moves the user off any OTHER zone they previously coordinated,
      // because coordinatedZoneId is a single column ÔÇö overwriting it is the move.
      await (tx as any).user.update({
        where: { id: userId },
        data: { coordinatedZoneId: zoneId },
      });
    });
  }

  // ÔöÇÔöÇÔöÇ findZones / findMunicipios ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  // ÔöÇÔöÇÔöÇ findUsers (admin) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async findUsers(): Promise<UserListItem[]> {
    // Projection explicitly excludes passwordHash ÔÇö never expose credentials.
    return this.prisma.user.findMany({
      select: {
        id: true,
        email: true,
        role: true,
        mustChangePassword: true,
        coordinatedZoneId: true,
        createdAt: true,
      },
      orderBy: { email: 'asc' },
    });
  }

  async findZones(): Promise<Zone[]> {
    return this.zoneRepo.findMany();
  }

  async findMunicipios(): Promise<Municipio[]> {
    return this.municipioRepo.findMany();
  }

  // ÔöÇÔöÇÔöÇ Zone CRUD ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  // NOTE: All zone/municipio direct Prisma calls are delegated to ScopedZoneRepository /
  // ScopedMunicipioRepository because those files are the only sanctioned locations for
  // raw prisma.zone.* / prisma.municipio.* calls (C1 meta-guard ÔÇö scope-meta-guard.spec.ts).

  async createZone(params: { name: string }): Promise<{ id: string }> {
    try {
      const zone = await this.zoneRepo.create({ name: params.name });
      return { id: zone.id };
    } catch (err) {
      if (this.isPrismaUniqueError(err)) {
        throw new ZoneNameInUseError(params.name);
      }
      throw err;
    }
  }

  async updateZone(id: string, params: { name: string }): Promise<Zone> {
    // Pre-check existence (without scope) to give ZoneNotFoundError instead of P2025
    const existing = await this.zoneRepo.findByIdForWrite(id);
    if (!existing) {
      throw new ZoneNotFoundError(id);
    }
    try {
      return await this.zoneRepo.update(id, { name: params.name });
    } catch (err) {
      if (this.isPrismaUniqueError(err)) {
        throw new ZoneNameInUseError(params.name);
      }
      throw err;
    }
  }

  async deleteZone(id: string): Promise<void> {
    const existing = await this.zoneRepo.findByIdForWrite(id);
    if (!existing) {
      throw new ZoneNotFoundError(id);
    }
    const counts = await this.zoneRepo.countDependents(id);
    if (counts.municipios > 0 || counts.supervisors > 0 || counts.coordinador) {
      throw new ZoneHasDependentsError(id);
    }
    await this.zoneRepo.delete(id);
  }

  // ÔöÇÔöÇÔöÇ Municipio CRUD ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async createMunicipio(params: { name: string; zoneId: string }): Promise<{ id: string }> {
    // Validate zone exists first ÔÇö gives a clear ZoneNotFoundError instead of FK violation
    const zone = await this.zoneRepo.findByIdForWrite(params.zoneId);
    if (!zone) {
      throw new ZoneNotFoundError(params.zoneId);
    }
    try {
      const municipio = await this.municipioRepo.create({ name: params.name, zoneId: params.zoneId });
      return { id: municipio.id };
    } catch (err) {
      if (this.isPrismaUniqueError(err)) {
        throw new MunicipioNameInUseError(params.name, params.zoneId);
      }
      throw err;
    }
  }

  async updateMunicipio(
    id: string,
    params: { name?: string; zoneId?: string },
  ): Promise<Municipio> {
    const existing = await this.municipioRepo.findByIdForWrite(id);
    if (!existing) {
      throw new MunicipioNotFoundError(id);
    }

    // If changing zone, validate new zone exists
    if (params.zoneId !== undefined) {
      const zone = await this.zoneRepo.findByIdForWrite(params.zoneId);
      if (!zone) {
        throw new ZoneNotFoundError(params.zoneId);
      }
    }

    // Build update data (only provided fields)
    const data: { name?: string; zoneId?: string } = {};
    if (params.name !== undefined) data.name = params.name;
    if (params.zoneId !== undefined) data.zoneId = params.zoneId;

    try {
      return await this.municipioRepo.update(id, data);
    } catch (err) {
      if (this.isPrismaUniqueError(err)) {
        const effectiveName = params.name ?? existing.name;
        const effectiveZoneId = params.zoneId ?? existing.zoneId;
        throw new MunicipioNameInUseError(effectiveName, effectiveZoneId);
      }
      throw err;
    }
  }

  async deleteMunicipio(id: string): Promise<void> {
    const existing = await this.municipioRepo.findByIdForWrite(id);
    if (!existing) {
      throw new MunicipioNotFoundError(id);
    }
    const supCount = await this.municipioRepo.countSupervisors(id);
    if (supCount > 0) {
      throw new MunicipioHasDependentsError(id);
    }
    await this.municipioRepo.delete(id);
  }

  // ÔöÇÔöÇÔöÇ Helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private isPrismaUniqueError(err: unknown): boolean {
    return (
      typeof err === 'object' &&
      err !== null &&
      'code' in err &&
      (err as { code: unknown }).code === 'P2002'
    );
  }
}

/**
 * T-09 RED ÔåÆ T-10 GREEN: ScopedAttendanceRepository unit spec.
 *
 * Covers:
 * - findByCheckOutClientRef: delegates to findFirstScoped with { checkOutClientRef }
 * - findByOperarioAndDate: delegates to findFirstScoped with { operarioId, date }
 *
 * Pattern mirrors scoped-novedad.repository.spec.ts (created in PR-A).
 * findFirstScoped merges scope filter as AND clause, so assertions check
 * that the WHERE passed to the delegate includes the expected fields.
 */

import { ScopedAttendanceRepository } from './scoped-attendance.repository';
import type { Attendance } from '@prisma/client';

function makeAttendance(overrides: Partial<Attendance> = {}): Attendance {
  return {
    id: 'ATT-1',
    supervisorId: 'S1',
    operarioId: 'O1',
    zoneId: 'Z1',
    date: '2026-05-31',
    checkInCapturedAt: new Date(),
    checkInReceivedAt: new Date(),
    checkInLat: 7.5,
    checkInLng: -76.5,
    checkInAccuracy: 10,
    checkOutCapturedAt: null,
    checkOutReceivedAt: null,
    checkOutLat: null,
    checkOutLng: null,
    checkOutAccuracy: null,
    checkInVerification: null,
    checkOutVerification: null,
    signatureKey: 'sig-key',
    checkOutSignatureKey: null,
    clientRef: 'REF-A',
    checkOutClientRef: 'CREF-Z',
    completedAt: new Date(),
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makeRepo(findFirstResult: Attendance | null) {
  const delegate = {
    findFirst: jest.fn().mockResolvedValue(findFirstResult),
    findMany: jest.fn().mockResolvedValue([]),
    create: jest.fn(),
    update: jest.fn(),
  };

  const scopeHolder = {
    current: () => ({ role: 'SUPERVISOR', supervisorId: 'S1', zoneId: 'Z1', userId: 'U1' }),
  };

  // Provide a minimal PrismaService-like object
  const prisma = { attendance: delegate } as any;
  const repo = new ScopedAttendanceRepository(
    prisma,
    scopeHolder as unknown as import('../../auth/domain/scope-context').ScopeContextHolder,
  );

  return { repo, delegate };
}

describe('ScopedAttendanceRepository ÔÇö PR-B additions', () => {
  describe('findByCheckOutClientRef', () => {
    it('returns attendance when found by checkOutClientRef', async () => {
      const att = makeAttendance({ checkOutClientRef: 'CREF-Z' });
      const { repo, delegate } = makeRepo(att);

      const result = await repo.findByCheckOutClientRef('CREF-Z');

      expect(result).toBe(att);
      expect(delegate.findFirst).toHaveBeenCalledTimes(1);
      // The WHERE clause must include checkOutClientRef
      const callArg = delegate.findFirst.mock.calls[0][0];
      const whereStr = JSON.stringify(callArg.where);
      expect(whereStr).toContain('checkOutClientRef');
      expect(whereStr).toContain('CREF-Z');
    });

    it('returns null when not found', async () => {
      const { repo } = makeRepo(null);
      const result = await repo.findByCheckOutClientRef('NONEXISTENT');
      expect(result).toBeNull();
    });
  });

  describe('findByOperarioAndDate', () => {
    it('returns attendance when found by operarioId+date', async () => {
      const att = makeAttendance({ operarioId: 'O1', date: '2026-05-31' });
      const { repo, delegate } = makeRepo(att);

      const result = await repo.findByOperarioAndDate('O1', '2026-05-31');

      expect(result).toBe(att);
      expect(delegate.findFirst).toHaveBeenCalledTimes(1);
      const callArg = delegate.findFirst.mock.calls[0][0];
      const whereStr = JSON.stringify(callArg.where);
      expect(whereStr).toContain('operarioId');
      expect(whereStr).toContain('O1');
      expect(whereStr).toContain('date');
      expect(whereStr).toContain('2026-05-31');
    });

    it('returns null when not found', async () => {
      const { repo } = makeRepo(null);
      const result = await repo.findByOperarioAndDate('UNKNOWN', '2026-01-01');
      expect(result).toBeNull();
    });
  });

  // ÔöÇÔöÇ findCompletedInRange (A7.1 ÔÇö AttendanceReaderPort) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  describe('findCompletedInRange', () => {
    it('A7-01: delegates to findManyScoped with operarioId + date range + completedAt not null', async () => {
      const { repo, delegate } = makeRepo(null);
      delegate.findMany.mockResolvedValue([]);
      await repo.findCompletedInRange('O1', '2026-05-01', '2026-05-15');

      expect(delegate.findMany).toHaveBeenCalledTimes(1);
      const callArg = delegate.findMany.mock.calls[0][0];
      const whereStr = JSON.stringify(callArg.where);
      expect(whereStr).toContain('operarioId');
      expect(whereStr).toContain('O1');
      expect(whereStr).toContain('date');
      expect(whereStr).toContain('2026-05-01');
      expect(whereStr).toContain('2026-05-15');
      expect(whereStr).toContain('completedAt');
    });

    it('A7-02: returns empty array when no completed attendances in range', async () => {
      const { repo, delegate } = makeRepo(null);
      delegate.findMany.mockResolvedValue([]);

      const result = await repo.findCompletedInRange('O1', '2026-05-01', '2026-05-15');

      expect(result).toEqual([]);
    });
  });

  // ÔöÇÔöÇ Delta ?since= branch (sync-delta-pull) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  describe('findMany (with optional since)', () => {
    it('SD-REPO-01: calls findManyScoped with empty where when since is undefined', async () => {
      const { repo, delegate } = makeRepo(null);
      await repo.findMany(undefined);
      expect(delegate.findMany).toHaveBeenCalledTimes(1);
      const callArg = delegate.findMany.mock.calls[0][0];
      expect(callArg.where).not.toHaveProperty('updatedAt');
    });

    it('SD-REPO-02: calls findManyScoped with updatedAt.gte when since is provided', async () => {
      const { repo, delegate } = makeRepo(null);
      const since = new Date('2026-05-31T12:00:00.000Z');
      await repo.findMany(since);
      expect(delegate.findMany).toHaveBeenCalledTimes(1);
      const callArg = delegate.findMany.mock.calls[0][0];
      const whereStr = JSON.stringify(callArg.where);
      expect(whereStr).toContain('updatedAt');
      expect(whereStr).toContain('gte');
    });
  });
});

/**
 * T-20 ÔÇö Unit tests for ScopedMunicipioRepository.
 *
 * Written FIRST (TDD red phase) ÔÇö fails before the repository exists.
 *
 * Verifies:
 * - COORDINADOR with zoneId ÔåÆ applyScopeFilter returns { zoneId } where-fragment
 *   (uses SCOPE_MAPS.Municipio zonePath).
 * - SUPERVISOR ÔåÆ structural deny { id: { in: [] } } (supervisorPath returns impossible predicate).
 * - GLOBAL_ROLES ÔåÆ pass-through.
 * - Unknown role "GHOST" ÔåÆ structural deny (fail-closed, INV-01).
 */

import { ScopedMunicipioRepository } from './scoped-municipio.repository';
import { applyScopeFilter } from '../domain/scope-filter';
import type { ScopeContext, ScopeContextHolder } from '../../auth/domain/scope-context';

// ÔöÇÔöÇÔöÇ Test doubles ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

interface FakeDelegate {
  findMany(args: unknown): Promise<unknown[]>;
  findFirst(args: unknown): Promise<unknown | null>;
}

function makeDelegate(rows: unknown[] = []): FakeDelegate {
  return {
    findMany: jest.fn().mockResolvedValue(rows),
    findFirst: jest.fn().mockResolvedValue(rows[0] ?? null),
  };
}

function makeHolder(ctx: ScopeContext): ScopeContextHolder {
  return {
    current: () => ctx,
    set: () => {},
  } as unknown as ScopeContextHolder;
}

function makePrisma(delegate: FakeDelegate): { municipio: FakeDelegate } {
  return { municipio: delegate };
}

