        .expect(200);

      const user = await prisma.user.findUnique({ where: { id: freshCoordId } });
      expect(user?.coordinatedZoneId).toBe(zoneBajoCaucaId);

      // Restore state
      await prisma.user.update({ where: { id: freshCoordId }, data: { coordinatedZoneId: null } });
    });

    it('Scenario 2.9 ÔÇö SUPERVISOR caller ÔåÆ 403', async () => {
      await request(app.getHttpServer())
        .post('/org/coordinadores/assign')
        .set('Authorization', `Bearer ${tokenSupervisor}`)
        .send({ userId: freshCoordId, zoneId: zoneUrabaId })
        .expect(403);
    });

    it('Scenario 2.10 ÔÇö COORDINADOR caller ÔåÆ 403', async () => {
      await request(app.getHttpServer())
        .post('/org/coordinadores/assign')
        .set('Authorization', `Bearer ${tokenCoordUraba}`)
        .send({ userId: freshCoordId, zoneId: zoneUrabaId })
        .expect(403);
    });
  });

  // ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
  // D3 ÔÇö Management-User Provisioning (incl. privilege-escalation guard)
  // ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ

  describe('D3 ÔÇö Provision management user (POST /org/users)', () => {
    it('Scenario 3.1 ÔÇö SYSTEM_ADMIN provisions GERENCIA (201, mustChangePassword=true)', async () => {
      const email = 'gerencia-provision-1@futuragest.co';
      const resp = await request(app.getHttpServer())
        .post('/org/users')
        .set('Authorization', `Bearer ${tokenAdmin}`)
        .send({ email, password: 'Temp1234!', role: 'GERENCIA' })
        .expect(201);

      expect(resp.body).toHaveProperty('id');

      const user = await prisma.user.findUnique({ where: { email } });
      expect(user).not.toBeNull();
      expect(user!.role).toBe('GERENCIA');
      expect(user!.mustChangePassword).toBe(true);
      expect(user!.coordinatedZoneId).toBeNull();
      // Password must be argon2-hashed (not plaintext)
      expect(user!.passwordHash).toMatch(/^\$argon2/);
      expect(user!.passwordHash).not.toBe('Temp1234!');

      // Cleanup
      await prisma.user.delete({ where: { email } });
    });

    it('Scenario 3.2 ÔÇö SYSTEM_ADMIN provisions LIDER_OPERATIVO (201)', async () => {
      const email = 'lider-provision-1@futuragest.co';
      const resp = await request(app.getHttpServer())
        .post('/org/users')
        .set('Authorization', `Bearer ${tokenAdmin}`)
        .send({ email, password: 'Temp1234!', role: 'LIDER_OPERATIVO' })
        .expect(201);

      expect(resp.body).toHaveProperty('id');

      const user = await prisma.user.findUnique({ where: { email } });
      expect(user?.mustChangePassword).toBe(true);
      expect(user?.coordinatedZoneId).toBeNull();

      await prisma.user.delete({ where: { email } });
    });

    it('Scenario 3.3 ÔÇö blocked role SUPERVISOR ÔåÆ 400', async () => {
      await request(app.getHttpServer())
        .post('/org/users')
        .set('Authorization', `Bearer ${tokenAdmin}`)
        .send({ email: 'sup-blocked@futuragest.co', password: 'Temp1234!', role: 'SUPERVISOR' })
        .expect(400);

      // No user created
      const count = await prisma.user.count({ where: { email: 'sup-blocked@futuragest.co' } });
      expect(count).toBe(0);
    });

    it('Scenario 3.5 ÔÇö duplicate email ÔåÆ 409', async () => {
      const email = 'dup-email-test@futuragest.co';

      // Create first user
      await request(app.getHttpServer())
        .post('/org/users')
        .set('Authorization', `Bearer ${tokenAdmin}`)
        .send({ email, password: 'Temp1234!', role: 'GERENCIA' })
        .expect(201);

      // Attempt duplicate
      await request(app.getHttpServer())
        .post('/org/users')
        .set('Authorization', `Bearer ${tokenAdmin}`)
        .send({ email, password: 'Temp1234!', role: 'TALENTO_HUMANO' })
        .expect(409);

      // Exactly one row remains
      const count = await prisma.user.count({ where: { email } });
      expect(count).toBe(1);

      // Cleanup
      await prisma.user.delete({ where: { email } });
    });

    it('Scenario 3.6 ÔÇö GERENCIA caller ÔåÆ 403 (route-level guard)', async () => {
      await request(app.getHttpServer())
        .post('/org/users')
        .set('Authorization', `Bearer ${tokenGerencia}`)
        .send({ email: 'blocked@futuragest.co', password: 'Temp1234!', role: 'LIDER_OPERATIVO' })
        .expect(403);

      // No user created
      const count = await prisma.user.count({ where: { email: 'blocked@futuragest.co' } });
      expect(count).toBe(0);
    });

    it('Scenario 3.9 ÔÇö TALENTO_HUMANO provisions TALENTO_HUMANO (201)', async () => {
      const email = 'talento-provision-2@futuragest.co';
      const resp = await request(app.getHttpServer())
        .post('/org/users')
        .set('Authorization', `Bearer ${tokenTalento}`)
        .send({ email, password: 'Temp1234!', role: 'TALENTO_HUMANO' })
        .expect(201);

      expect(resp.body).toHaveProperty('id');
      const user = await prisma.user.findUnique({ where: { email } });
      expect(user?.role).toBe('TALENTO_HUMANO');
      expect(user?.mustChangePassword).toBe(true);

      await prisma.user.delete({ where: { email } });
    });

    it('Scenario 3.10 ÔÇö TALENTO_HUMANO provisions LIDER_OPERATIVO (201)', async () => {
      const email = 'lider-provision-2@futuragest.co';
      const resp = await request(app.getHttpServer())
        .post('/org/users')
        .set('Authorization', `Bearer ${tokenTalento}`)
        .send({ email, password: 'Temp1234!', role: 'LIDER_OPERATIVO' })
        .expect(201);

      expect(resp.body).toHaveProperty('id');
      await prisma.user.delete({ where: { email } });
    });

    /**
     * Scenario 3.11 ÔÇö MANDATORY GATE
     *
     * TALENTO_HUMANO attempting to provision GERENCIA MUST return 403.
     * This is the CRITICAL end-to-end proof that:
     * 1. ProvisionManagementUserUseCase is REQUEST-SCOPED (not singleton).
     * 2. ScopeContextHolder.current() returns the per-request actor role (TALENTO_HUMANO).
     * 3. The privilege-escalation guard compares actor rank (2) vs target rank (3) ÔåÆ ForbiddenException.
     * 4. OrgController maps ForbiddenException ÔåÆ HTTP 403.
     *
     * If this test FAILS with 201, it means the use-case was registered as a singleton
     * (empty ScopeContext, actor role undefined ÔåÆ bypasses the rank check).
     */
    it('Scenario 3.11 ÔÇö TALENTO_HUMANO ÔåÆ GERENCIA ÔåÆ 403 (privilege-escalation guard, request-scoped DI)', async () => {
      const email = 'gerencia-escalation-blocked@futuragest.co';

      await request(app.getHttpServer())
        .post('/org/users')
        .set('Authorization', `Bearer ${tokenTalento}`)
        .send({ email, password: 'Temp1234!', role: 'GERENCIA' })
        .expect(403);

      // No user should have been created
      const count = await prisma.user.count({ where: { email } });
      expect(count).toBe(0);
    });

    it('Scenario 3.12 ÔÇö SYSTEM_ADMIN provisions all three management roles', async () => {
      const emails = {
        gerencia: 'gerencia-allthree-1@futuragest.co',
        talento: 'talento-allthree-1@futuragest.co',
        lider: 'lider-allthree-1@futuragest.co',
      };

      for (const [role, email] of [
        ['GERENCIA', emails.gerencia],
        ['TALENTO_HUMANO', emails.talento],
        ['LIDER_OPERATIVO', emails.lider],
      ] as [string, string][]) {
        await request(app.getHttpServer())
          .post('/org/users')
          .set('Authorization', `Bearer ${tokenAdmin}`)
          .send({ email, password: 'Temp1234!', role })
          .expect(201);
      }

      // Verify all three were created
      for (const email of Object.values(emails)) {
        const count = await prisma.user.count({ where: { email } });
        expect(count).toBe(1);
      }

      // Cleanup
      await prisma.user.deleteMany({
        where: { email: { in: Object.values(emails) } },
      });
    });
  });

  describe('D5 ÔÇö GET /org/users (admin user listing)', () => {
    it('SYSTEM_ADMIN lists users without exposing passwordHash', async () => {
      const resp = await request(app.getHttpServer())
        .get('/org/users')
        .set('Authorization', `Bearer ${tokenAdmin}`)
        .expect(200);

      const users = resp.body as Array<Record<string, unknown>>;
      expect(Array.isArray(users)).toBe(true);
      expect(users.length).toBeGreaterThan(0);
      for (const u of users) {
        expect(u).toHaveProperty('email');
        expect(u).toHaveProperty('role');
        expect(u).not.toHaveProperty('passwordHash');
      }
    });

    it('SUPERVISOR is forbidden (403)', async () => {
      await request(app.getHttpServer())
        .get('/org/users')
        .set('Authorization', `Bearer ${tokenSupervisor}`)
        .expect(403);
    });
  });
});

/**
 * SUP-01..06 ÔÇö Create Supervisor Integration Suite.
 *
 * POST /iam/supervisors ÔÇö compound User + Supervisor write.
 *
 * Scenarios:
 *   SUP-01 ÔÇö SYSTEM_ADMIN creates supervisor (happy path): 201 { id },
 *            User row has role SUPERVISOR + mustChangePassword=true,
 *            Supervisor row linked correctly.
 *   SUP-02 ÔÇö TALENTO_HUMANO creates supervisor: 201 (same write roles).
 *   SUP-03 ÔÇö Duplicate email ÔåÆ 409 Conflict.
 *   SUP-04 ÔÇö Bad area value ÔåÆ 400 (ValidationPipe rejects before handler).
 *   SUP-05 ÔÇö Municipio not in zone ÔåÆ 400.
 *   SUP-06 ÔÇö SUPERVISOR role caller ÔåÆ 403 (wrong role).
 *
 * Teardown: FK-safe order (Supervisor ÔåÆ DeviceSession ÔåÆ User).
 * Uses seeded zones/municipios from jest-global-setup.ts.
 */

import { Test, TestingModule } from '@nestjs/testing';
import { INestApplication, ValidationPipe } from '@nestjs/common';
// eslint-disable-next-line @typescript-eslint/no-require-imports
const request: import('supertest').SuperTestStatic = require('supertest');
import { AppModule } from '../../app.module';
import { createPrismaClient } from '../../database/prisma-client';
import type { PrismaClient } from '@prisma/client';
import * as argon2 from 'argon2';
import * as jwt from 'jsonwebtoken';
import { STORAGE_PORT } from '../storage/domain/storage.port';

// ÔöÇÔöÇÔöÇ Constants ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

const DEV_JWT_SECRET = 'futuragest-dev-secret-do-not-use-in-production';
const TEST_DEVICE = 'sup-create-test-device';
const TEST_PASSWORD = 'TestPass123!';

function mintToken(claims: {
  sub: string;
  role: string;
  zoneId?: string;
  supervisorId?: string;
  mustChangePassword?: boolean;
}): string {
  return jwt.sign(
    {
      sub: claims.sub,
      role: claims.role,
      zoneId: claims.zoneId,
      supervisorId: claims.supervisorId,
      deviceId: TEST_DEVICE,
      mustChangePassword: claims.mustChangePassword ?? false,
    },
    DEV_JWT_SECRET,
    { expiresIn: '15m' },
  );
}

const mockStoragePort = {
  putObject: jest.fn().mockResolvedValue(undefined),
  getPresignedGetUrl: jest.fn().mockResolvedValue('https://minio.example/presigned'),
  getPresignedPutUrl: jest.fn().mockResolvedValue('https://minio.example/presigned-put'),
  removeObject: jest.fn().mockResolvedValue(undefined),
};

// ÔöÇÔöÇÔöÇ Suite ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

describe('Create Supervisor Integration Suite (SUP-01..06)', () => {
  let app: INestApplication;
  let prisma: PrismaClient;

  // Fixture ids
  let zoneZ1Id: string;
  let zoneZ2Id: string;        // Different zone for municipio-mismatch test
  let municipioM1Id: string;   // In zoneZ1
  let municipioM2Id: string;   // In zoneZ2 (for mismatch test)
  let adminUserId: string;
  let talentoUserId: string;
  let existingSupervisorUserId: string;
  let existingSupervisorId: string;

  // Tokens
  let tokenAdmin: string;
  let tokenTalento: string;
  let tokenSupervisor: string;

  // Cleanup tracking
  const createdUserIds: string[] = [];
  const createdSupervisorIds: string[] = [];

  // ÔöÇÔöÇÔöÇ Setup ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  beforeAll(async () => {
    const moduleRef: TestingModule = await Test.createTestingModule({
      imports: [AppModule],
    })
      .overrideProvider(STORAGE_PORT)
      .useValue(mockStoragePort)
      .compile();

    app = moduleRef.createNestApplication();
    app.useGlobalPipes(new ValidationPipe({ whitelist: true }));
    await app.init();

    prisma = createPrismaClient();

    // Resolve seeded zones
    const zoneUraba = await prisma.zone.findFirst({ where: { name: 'Zona Urab├í' } });
    if (!zoneUraba) throw new Error('Seeded zone Zona Urab├í not found');
    zoneZ1Id = zoneUraba.id;

    // Pick a second zone for the mismatch test ÔÇö any zone that is not zoneZ1
    const zoneTwo = await prisma.zone.findFirst({ where: { id: { not: zoneZ1Id } } });
    if (!zoneTwo) throw new Error('Need at least 2 seeded zones for mismatch test');
    zoneZ2Id = zoneTwo.id;

    // Resolve seeded municipio in zoneZ1
    const muni1 = await prisma.municipio.findFirst({ where: { zoneId: zoneZ1Id } });
    if (!muni1) throw new Error('No seeded municipio in Zona Urab├í');
    municipioM1Id = muni1.id;

    // Resolve or create a municipio in zoneZ2 for the mismatch test
    let muni2 = await prisma.municipio.findFirst({ where: { zoneId: zoneZ2Id } });
    if (!muni2) {
      muni2 = await prisma.municipio.create({
        data: { name: 'Test-Muni-Z2', zoneId: zoneZ2Id },
      });
    }
    municipioM2Id = muni2.id;

    const passwordHash = await argon2.hash(TEST_PASSWORD);

    // Clean leftover fixture users
    const fixtureEmails = [
      'admin-sup-create-test@futuragest.co',
      'talento-sup-create-test@futuragest.co',
      'existing-sup-create-test@futuragest.co',
    ];
    const leftover = await prisma.user.findMany({
      where: { email: { in: fixtureEmails } },
      select: { id: true },
    });
    if (leftover.length > 0) {
      const ids = leftover.map((u) => u.id);
      const sups = await prisma.supervisor.findMany({ where: { userId: { in: ids } }, select: { id: true } });
      const supIds = sups.map((s) => s.id);
      if (supIds.length > 0) {
        await prisma.novedad.deleteMany({ where: { supervisorId: { in: supIds } } });
        await prisma.attendance.deleteMany({ where: { supervisorId: { in: supIds } } });
        await prisma.operario.deleteMany({ where: { supervisorId: { in: supIds } } });
        await prisma.supervisor.deleteMany({ where: { id: { in: supIds } } });
      }
      await prisma.deviceSession.deleteMany({ where: { userId: { in: ids } } });
      await prisma.user.deleteMany({ where: { id: { in: ids } } });
    }

    // Admin user
    const adminUser = await prisma.user.create({
      data: { email: 'admin-sup-create-test@futuragest.co', passwordHash, role: 'SYSTEM_ADMIN', mustChangePassword: false },
    });
    adminUserId = adminUser.id;
    createdUserIds.push(adminUserId);
    await prisma.deviceSession.create({
      data: { userId: adminUserId, deviceId: TEST_DEVICE, refreshTokenHash: await argon2.hash('dummy') },
    });

    // TALENTO_HUMANO user
    const talentoUser = await prisma.user.create({
      data: { email: 'talento-sup-create-test@futuragest.co', passwordHash, role: 'TALENTO_HUMANO', mustChangePassword: false },
    });
    talentoUserId = talentoUser.id;
    createdUserIds.push(talentoUserId);
    await prisma.deviceSession.create({
      data: { userId: talentoUserId, deviceId: TEST_DEVICE, refreshTokenHash: await argon2.hash('dummy') },
    });

    // Existing supervisor (for SUP-06 forbidden test + SUP-03 email collision)
    const existingSupUser = await prisma.user.create({
      data: { email: 'existing-sup-create-test@futuragest.co', passwordHash, role: 'SUPERVISOR', mustChangePassword: false },
    });
    existingSupervisorUserId = existingSupUser.id;
    createdUserIds.push(existingSupervisorUserId);
    await prisma.deviceSession.create({
      data: { userId: existingSupervisorUserId, deviceId: TEST_DEVICE, refreshTokenHash: await argon2.hash('dummy') },
    });
    const existingSup = await prisma.supervisor.create({
      data: { userId: existingSupervisorUserId, municipioId: municipioM1Id, zoneId: zoneZ1Id, area: 'BARRIDO' },
    });
    existingSupervisorId = existingSup.id;
    createdSupervisorIds.push(existingSupervisorId);

    // Mint tokens
    tokenAdmin = mintToken({ sub: adminUserId, role: 'SYSTEM_ADMIN' });
    tokenTalento = mintToken({ sub: talentoUserId, role: 'TALENTO_HUMANO' });
    tokenSupervisor = mintToken({ sub: existingSupervisorUserId, role: 'SUPERVISOR', supervisorId: existingSupervisorId, zoneId: zoneZ1Id });
  }, 30_000);

  afterAll(async () => {
    // FK-safe cleanup: Operario ÔåÆ Supervisor ÔåÆ DeviceSession ÔåÆ User
    // Remove any supervisors created by the tests (tracked by id lookups)
    if (createdSupervisorIds.length > 0) {
      await prisma.operario.deleteMany({ where: { supervisorId: { in: createdSupervisorIds } } });
      await prisma.supervisor.deleteMany({ where: { id: { in: createdSupervisorIds } } });
    }
    // Remove all user-side fixtures (DeviceSessions + Users)
    for (const userId of createdUserIds) {
      await prisma.deviceSession.deleteMany({ where: { userId } });
    }
    if (createdUserIds.length > 0) {
      await prisma.user.deleteMany({ where: { id: { in: createdUserIds } } });
    }

    await prisma.$disconnect();
    await app.close();
  });

  // ÔöÇÔöÇÔöÇ Helper ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  /**
   * Builds a valid create-supervisor body; individual fields can be overridden.
   * Uses a timestamp-based email to guarantee uniqueness across test runs.
   */
  function makeBody(overrides: Partial<{
    email: string;
    password: string;
    area: string;
    zoneId: string;
    municipioId: string;
  }> = {}) {
    return {
      email: `sup-${Date.now()}-${Math.random().toString(36).slice(2, 6)}@test.co`,
      password: 'Secure1234!',
      area: 'BARRIDO',
      zoneId: zoneZ1Id,
      municipioId: municipioM1Id,
      ...overrides,
    };
  }

  // ÔöÇÔöÇÔöÇ SUP-01 ÔÇö Happy path (SYSTEM_ADMIN) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SUP-01 ÔÇö SYSTEM_ADMIN creates supervisor: 201, User + Supervisor persisted correctly', async () => {
    const body = makeBody();

    const resp = await request(app.getHttpServer())
      .post('/iam/supervisors')
      .set('Authorization', `Bearer ${tokenAdmin}`)
      .send(body)
      .expect(201);

    expect(resp.body).toHaveProperty('id');
    const supId = resp.body.id as string;
    createdSupervisorIds.push(supId);

    // Verify Supervisor row
    const sup = await prisma.supervisor.findUnique({ where: { id: supId } });
    expect(sup).not.toBeNull();
    expect(sup!.zoneId).toBe(zoneZ1Id);
    expect(sup!.municipioId).toBe(municipioM1Id);
    expect(sup!.area).toBe('BARRIDO');

    // Verify User row
    const user = await prisma.user.findUnique({ where: { id: sup!.userId } });
    expect(user).not.toBeNull();
    expect(user!.email).toBe(body.email);
    expect(user!.role).toBe('SUPERVISOR');
    expect(user!.mustChangePassword).toBe(true);
    // passwordHash must never equal the plaintext
    expect(user!.passwordHash).not.toBe(body.password);

    // Track user for cleanup
    createdUserIds.push(user!.id);
  });

  // ÔöÇÔöÇÔöÇ SUP-02 ÔÇö TALENTO_HUMANO ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SUP-02 ÔÇö TALENTO_HUMANO creates supervisor: 201', async () => {
    const body = makeBody({ area: 'RECOLECCION' });

    const resp = await request(app.getHttpServer())
      .post('/iam/supervisors')
      .set('Authorization', `Bearer ${tokenTalento}`)
      .send(body)
      .expect(201);

    const supId = resp.body.id as string;
    createdSupervisorIds.push(supId);

    const sup = await prisma.supervisor.findUnique({ where: { id: supId } });
    expect(sup!.area).toBe('RECOLECCION');
    const user = await prisma.user.findUnique({ where: { id: sup!.userId } });
    createdUserIds.push(user!.id);
  });

  // ÔöÇÔöÇÔöÇ SUP-03 ÔÇö Duplicate email ÔåÆ 409 ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SUP-03 ÔÇö Duplicate email ÔåÆ 409, no partial rows', async () => {
    const body = makeBody({ email: 'existing-sup-create-test@futuragest.co' });

    await request(app.getHttpServer())
      .post('/iam/supervisors')
      .set('Authorization', `Bearer ${tokenAdmin}`)
      .send(body)
      .expect(409);

    // Supervisor count for that email must remain 1 (the pre-created fixture)
    const user = await prisma.user.findUnique({ where: { email: body.email } });
    expect(user).not.toBeNull(); // user exists (fixture)
    const supCount = await prisma.supervisor.count({ where: { userId: user!.id } });
    expect(supCount).toBe(1);
  });

  // ÔöÇÔöÇÔöÇ SUP-04 ÔÇö Bad area ÔåÆ 400 (ValidationPipe) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SUP-04 ÔÇö Invalid area value ÔåÆ 400', async () => {
    const body = makeBody({ area: 'INVALID_AREA' });

    await request(app.getHttpServer())
      .post('/iam/supervisors')
      .set('Authorization', `Bearer ${tokenAdmin}`)
      .send(body)
      .expect(400);
  });

  // ÔöÇÔöÇÔöÇ SUP-05 ÔÇö Municipio not in zone ÔåÆ 400 ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SUP-05 ÔÇö Municipio not in zone ÔåÆ 400', async () => {
    // zoneZ1Id + municipioM2Id (which belongs to zoneZ2) ÔåÆ mismatch
    const body = makeBody({ zoneId: zoneZ1Id, municipioId: municipioM2Id });

    await request(app.getHttpServer())
      .post('/iam/supervisors')
      .set('Authorization', `Bearer ${tokenAdmin}`)
      .send(body)
      .expect(400);
  });

  // ÔöÇÔöÇÔöÇ SUP-06 ÔÇö SUPERVISOR role ÔåÆ 403 ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SUP-06 ÔÇö SUPERVISOR caller ÔåÆ 403', async () => {
    const body = makeBody();

    await request(app.getHttpServer())
      .post('/iam/supervisors')
      .set('Authorization', `Bearer ${tokenSupervisor}`)
      .send(body)
      .expect(403);
  });

  // ÔöÇÔöÇÔöÇ No token ÔåÆ 401 ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('No token ÔåÆ 401', async () => {
    const body = makeBody();

    await request(app.getHttpServer())
      .post('/iam/supervisors')
      .send(body)
      .expect(401);
  });
});

/**
 * sync-delta-pull integration suite ÔÇö SD-01..SD-24
 *
 * Tests the ?since= delta filter across operarios, attendance, and novedades,
 * the operario tombstone delta mode, and the ?clientRef= attendance recovery
 * endpoint.
 *
 * Fixture setup:
 * - Zone Z1 (seeded): 'Zona Urab├í'
 * - Zone Z2 (seeded): 'Zona Bajo Cauca'
 * - Supervisor S1 in Z1, Supervisor S2 in Z2
 * - Operario O1 (active, under S1), Operario O2 (active, under S2)
 * - Attendance A1 (S1, O1), A2 (S2, O2)
 * - Novedad N1 on A1 (S1)
 *
 * cursor strategy: capture actual updatedAt from created entities (NOT new Date())
 * to avoid ms-resolution flakiness.
 *
 * Teardown: Novedad ÔåÆ Attendance ÔåÆ Operario ÔåÆ Supervisor ÔåÆ DeviceSession ÔåÆ User
 */

import { Test, TestingModule } from '@nestjs/testing';
import { INestApplication, ValidationPipe } from '@nestjs/common';
// eslint-disable-next-line @typescript-eslint/no-require-imports
const request: import('supertest').SuperTestStatic = require('supertest');
import { AppModule } from '../../app.module';
import { createPrismaClient } from '../../database/prisma-client';
import type { PrismaClient } from '@prisma/client';
import * as argon2 from 'argon2';
import * as jwt from 'jsonwebtoken';
import { STORAGE_PORT } from '../storage/domain/storage.port';

// ÔöÇÔöÇÔöÇ Constants ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

const DEV_JWT_SECRET = 'futuragest-dev-secret-do-not-use-in-production';
const TEST_DEVICE = 'delta-pull-test-device';
const TEST_PASSWORD = 'TestPass123!';

function mintToken(claims: {
  sub: string;
  role: string;
  zoneId?: string;
  supervisorId?: string;
  mustChangePassword?: boolean;
}): string {
  return jwt.sign(
    {
      sub: claims.sub,
      role: claims.role,
      zoneId: claims.zoneId,
      supervisorId: claims.supervisorId,
      deviceId: TEST_DEVICE,
      mustChangePassword: claims.mustChangePassword ?? false,
    },
    DEV_JWT_SECRET,
    { expiresIn: '15m' },
  );
}

const mockStoragePort = {
  putObject: jest.fn().mockResolvedValue(undefined),
  getPresignedGetUrl: jest.fn().mockResolvedValue('https://minio.example/presigned'),
  getPresignedPutUrl: jest.fn().mockResolvedValue('https://minio.example/presigned-put'),
  removeObject: jest.fn().mockResolvedValue(undefined),
};

// ÔöÇÔöÇÔöÇ Suite ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

describe('Sync Delta Pull Integration Suite (SD-01..SD-24)', () => {
  let app: INestApplication;
  let prisma: PrismaClient;

  // Fixture ids
  let zoneZ1Id: string;
  let zoneZ2Id: string;
  let s1UserId: string;
  let s2UserId: string;
  let s1Id: string;
  let s2Id: string;
  let o1Id: string;
  let o2Id: string;
  let municipioIdZ1: string;
  let municipioIdZ2: string;
  let adminUserId: string;

  // Tokens
  let tokenS1: string;
  let tokenS2: string;
  let tokenAdmin: string;

  // Cleanup tracking
  const createdUserIds: string[] = [];

  beforeAll(async () => {
    const moduleRef: TestingModule = await Test.createTestingModule({
      imports: [AppModule],
    })
      .overrideProvider(STORAGE_PORT)
      .useValue(mockStoragePort)
      .compile();

    app = moduleRef.createNestApplication();
    app.useGlobalPipes(new ValidationPipe({ whitelist: true }));
    await app.init();

    prisma = createPrismaClient();

    // Resolve seeded zones
    const zoneZ1 = await prisma.zone.findFirst({ where: { name: 'Zona Urab├í' } });
    const zoneZ2 = await prisma.zone.findFirst({ where: { name: 'Zona Bajo Cauca' } });
    if (!zoneZ1 || !zoneZ2) {
      throw new Error('Seeded zones not found ÔÇö run globalSetup first');
    }
    zoneZ1Id = zoneZ1.id;
    zoneZ2Id = zoneZ2.id;

    // Resolve seeded municipios
    const m1 = await prisma.municipio.findFirst({ where: { zoneId: zoneZ1Id } });
    const m2 = await prisma.municipio.findFirst({ where: { zoneId: zoneZ2Id } });
    if (!m1 || !m2) throw new Error('Seeded municipios not found');
    municipioIdZ1 = m1.id;
    municipioIdZ2 = m2.id;

    const passwordHash = await argon2.hash(TEST_PASSWORD);

    // Idempotent cleanup of leftovers
    const fixtureEmails = [
      's1-delta@futuragest.co',
      's2-delta@futuragest.co',
      'admin-delta@futuragest.co',
    ];
    const leftover = await prisma.user.findMany({
      where: { email: { in: fixtureEmails } },
      select: { id: true },
    });
    if (leftover.length > 0) {
      const leftoverIds = leftover.map((u) => u.id);
      const leftoverSups = await prisma.supervisor.findMany({
        where: { userId: { in: leftoverIds } },
        select: { id: true },
      });
      const leftoverSupIds = leftoverSups.map((s) => s.id);
      if (leftoverSupIds.length > 0) {
        const leftoverAtts = await prisma.attendance.findMany({
          where: { supervisorId: { in: leftoverSupIds } },
          select: { id: true },
        });
        const leftoverAttIds = leftoverAtts.map((a) => a.id);
        if (leftoverAttIds.length > 0) {
          await prisma.novedad.deleteMany({ where: { attendanceId: { in: leftoverAttIds } } });
        }
        await prisma.attendance.deleteMany({ where: { supervisorId: { in: leftoverSupIds } } });
        await prisma.operario.deleteMany({ where: { supervisorId: { in: leftoverSupIds } } });
        await prisma.supervisor.deleteMany({ where: { id: { in: leftoverSupIds } } });
      }
      await prisma.deviceSession.deleteMany({ where: { userId: { in: leftoverIds } } });
      await prisma.user.deleteMany({ where: { id: { in: leftoverIds } } });
    }

    async function createUser(email: string, role: string) {
      const user = await prisma.user.create({
        data: { email, passwordHash, role: role as any, mustChangePassword: false },
      });
      createdUserIds.push(user.id);
      await prisma.deviceSession.upsert({
        where: { userId_deviceId: { userId: user.id, deviceId: TEST_DEVICE } },
        update: { revokedAt: null },
        create: {
          userId: user.id,
          deviceId: TEST_DEVICE,
          refreshTokenHash: await argon2.hash('dummy-refresh'),
        },
      });
      return user;
    }

    const s1User = await createUser('s1-delta@futuragest.co', 'SUPERVISOR');
    s1UserId = s1User.id;
    const s1Sup = await prisma.supervisor.create({
      data: { userId: s1UserId, municipioId: municipioIdZ1, zoneId: zoneZ1Id, area: 'BARRIDO' },
    });
    s1Id = s1Sup.id;

    const s2User = await createUser('s2-delta@futuragest.co', 'SUPERVISOR');
    s2UserId = s2User.id;
    const s2Sup = await prisma.supervisor.create({
      data: { userId: s2UserId, municipioId: municipioIdZ2, zoneId: zoneZ2Id, area: 'BARRIDO' },
    });
    s2Id = s2Sup.id;

    const o1 = await prisma.operario.create({
      data: { fullName: 'Delta Op 1', documento: 'DELTA-DOC-001', supervisorId: s1Id },
    });
    o1Id = o1.id;

    const o2 = await prisma.operario.create({
      data: { fullName: 'Delta Op 2', documento: 'DELTA-DOC-002', supervisorId: s2Id },
    });
    o2Id = o2.id;

    const adminUser = await createUser('admin-delta@futuragest.co', 'SYSTEM_ADMIN');
    adminUserId = adminUser.id;

    tokenS1 = mintToken({ sub: s1UserId, role: 'SUPERVISOR', supervisorId: s1Id, zoneId: zoneZ1Id });
    tokenS2 = mintToken({ sub: s2UserId, role: 'SUPERVISOR', supervisorId: s2Id, zoneId: zoneZ2Id });
    tokenAdmin = mintToken({ sub: adminUserId, role: 'SYSTEM_ADMIN' });
  }, 60_000);

  afterAll(async () => {
    const supIds = [s1Id, s2Id].filter(Boolean);
    if (supIds.length > 0) {
      const atts = await prisma.attendance.findMany({
        where: { supervisorId: { in: supIds } },
        select: { id: true },
      });
      const attIds = atts.map((a) => a.id);
      if (attIds.length > 0) {
        await prisma.novedad.deleteMany({ where: { attendanceId: { in: attIds } } });
      }
      await prisma.attendance.deleteMany({ where: { supervisorId: { in: supIds } } });
      await prisma.operario.deleteMany({ where: { supervisorId: { in: supIds } } });
      await prisma.supervisor.deleteMany({ where: { id: { in: supIds } } });
    }
    for (const userId of createdUserIds) {
      await prisma.deviceSession.deleteMany({ where: { userId } });
    }
    if (createdUserIds.length > 0) {
      await prisma.user.deleteMany({ where: { id: { in: createdUserIds } } });
    }
    await prisma.$disconnect();
    await app.close();
  });

  // ÔöÇÔöÇÔöÇ SD-01: invalid ?since= ÔåÆ 400 ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SD-01: GET /iam/operarios?since=not-a-date ÔåÆ 400', async () => {
    const res = await request(app.getHttpServer())
      .get('/iam/operarios?since=not-a-date')
      .set('Authorization', `Bearer ${tokenAdmin}`);
    expect(res.status).toBe(400);
  });

  it('SD-02: GET /asistencia?since=not-a-date ÔåÆ 400', async () => {
    const res = await request(app.getHttpServer())
      .get('/asistencia?since=not-a-date')
      .set('Authorization', `Bearer ${tokenS1}`);
    expect(res.status).toBe(400);
  });

  it('SD-03: GET /novedades?since=not-a-date ÔåÆ 400', async () => {
    const res = await request(app.getHttpServer())
      .get('/novedades?since=not-a-date')
      .set('Authorization', `Bearer ${tokenS1}`);
    expect(res.status).toBe(400);
  });

  // ÔöÇÔöÇÔöÇ SD-04: no ?since= ÔåÆ full scoped list (backward compat) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SD-04: GET /iam/operarios (no since) ÔåÆ full list includes O1', async () => {
    const res = await request(app.getHttpServer())
      .get('/iam/operarios')
      .set('Authorization', `Bearer ${tokenS1}`);
    expect(res.status).toBe(200);
    const ids = res.body.map((o: any) => o.id);
    expect(ids).toContain(o1Id);
    expect(ids).not.toContain(o2Id); // scope-enforced
  });

  it('SD-05: GET /asistencia (no since) ÔåÆ 200 (backward compat)', async () => {
    const res = await request(app.getHttpServer())
      .get('/asistencia')
      .set('Authorization', `Bearer ${tokenS1}`);
    expect(res.status).toBe(200);
    expect(Array.isArray(res.body)).toBe(true);
  });

  it('SD-06: GET /novedades (no since) ÔåÆ 200 (backward compat)', async () => {
    const res = await request(app.getHttpServer())
      .get('/novedades')
      .set('Authorization', `Bearer ${tokenS1}`);
    expect(res.status).toBe(200);
    expect(Array.isArray(res.body)).toBe(true);
  });

  // ÔöÇÔöÇÔöÇ SD-07..SD-09: ?since= delta filter returns only changed rows ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SD-07: GET /iam/operarios?since= in the future ÔåÆ empty array (no changes yet)', async () => {
    const future = new Date(Date.now() + 60_000).toISOString();
    const res = await request(app.getHttpServer())
      .get(`/iam/operarios?since=${encodeURIComponent(future)}`)
      .set('Authorization', `Bearer ${tokenAdmin}`);
    expect(res.status).toBe(200);
    expect(res.body).toEqual([]);
  });

  it('SD-08: GET /iam/operarios?since= captures row updated after cursor', async () => {
    // Capture O1 updatedAt before modification
    const before = await prisma.operario.findUnique({ where: { id: o1Id } });
    expect(before).toBeTruthy();
    const cursorBefore = before!.updatedAt;

    // Modify O1 after cursor (small wait to ensure timestamp advances)
    await new Promise((r) => setTimeout(r, 10));
    await prisma.operario.update({ where: { id: o1Id }, data: { fullName: 'Delta Op 1 Modified' } });

    // Fetch updated O1 and use its actual updatedAt
    const after = await prisma.operario.findUnique({ where: { id: o1Id } });
    expect(after).toBeTruthy();

    // Since = cursor BEFORE the update ÔåÆ O1 should appear
    const since = cursorBefore.toISOString();
    const res = await request(app.getHttpServer())
      .get(`/iam/operarios?since=${encodeURIComponent(since)}`)
      .set('Authorization', `Bearer ${tokenAdmin}`);
    expect(res.status).toBe(200);
    const ids = res.body.map((o: any) => o.id);
    expect(ids).toContain(o1Id);
  });

  it('SD-09: GET /iam/operarios?since= with cursor AFTER update ÔåÆ O1 excluded', async () => {
    // Use current time as cursor (all rows have updatedAt <= now)
    const after = await prisma.operario.findUnique({ where: { id: o1Id } });
    expect(after).toBeTruthy();
    // Wait 10ms then use a cursor past the last update
    await new Promise((r) => setTimeout(r, 10));
    const cursor = new Date(after!.updatedAt.getTime() + 5).toISOString();
    const res = await request(app.getHttpServer())
      .get(`/iam/operarios?since=${encodeURIComponent(cursor)}`)
      .set('Authorization', `Bearer ${tokenAdmin}`);
    expect(res.status).toBe(200);
    const ids = res.body.map((o: any) => o.id);
    expect(ids).not.toContain(o1Id);
  });

  // ÔöÇÔöÇÔöÇ SD-10: tombstone inclusion in delta mode ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SD-10: operario delta mode includes deactivated tombstones (?since= present)', async () => {
    // Record time before deactivation
    const beforeDeact = await prisma.operario.findUnique({ where: { id: o2Id } });
    const cursor = new Date(beforeDeact!.updatedAt.getTime() - 1).toISOString();

    // Deactivate O2 (S2's operario ÔÇö admin can see all)
    await prisma.operario.update({ where: { id: o2Id }, data: { deactivatedAt: new Date() } });

    // Without ?since= ÔåÆ O2 is excluded by default (deactivatedAt != null)
    const noSince = await request(app.getHttpServer())
      .get('/iam/operarios')
      .set('Authorization', `Bearer ${tokenAdmin}`);
    expect(noSince.status).toBe(200);
    const noSinceIds = noSince.body.map((o: any) => o.id);
    expect(noSinceIds).not.toContain(o2Id);

    // With ?since= ÔåÆ O2 (tombstone) IS included in delta
    const res = await request(app.getHttpServer())
      .get(`/iam/operarios?since=${encodeURIComponent(cursor)}`)
      .set('Authorization', `Bearer ${tokenAdmin}`);
    expect(res.status).toBe(200);
    const ids = res.body.map((o: any) => o.id);
    expect(ids).toContain(o2Id);
  });

  // ÔöÇÔöÇÔöÇ SD-11: ?includeInactive in non-delta mode still works ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SD-11: GET /iam/operarios?includeInactive=true (no since) ÔåÆ includes deactivated', async () => {
    const res = await request(app.getHttpServer())
      .get('/iam/operarios?includeInactive=true')
      .set('Authorization', `Bearer ${tokenAdmin}`);
    expect(res.status).toBe(200);
    const ids = res.body.map((o: any) => o.id);
    expect(ids).toContain(o2Id); // deactivated O2 returned with includeInactive
  });

  // ÔöÇÔöÇÔöÇ SD-12..SD-15: attendance delta filter ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SD-12: GET /asistencia?since= future ÔåÆ empty (no attendance yet created)', async () => {
    const future = new Date(Date.now() + 60_000).toISOString();
    const res = await request(app.getHttpServer())
      .get(`/asistencia?since=${encodeURIComponent(future)}`)
      .set('Authorization', `Bearer ${tokenS1}`);
    expect(res.status).toBe(200);
    expect(res.body).toEqual([]);
  });

  it('SD-13: GET /asistencia?since= cursor before check-in ÔåÆ returns new record', async () => {
    const cursor = new Date(Date.now() - 500).toISOString();

    // Create an attendance via check-in
    const checkInRes = await request(app.getHttpServer())
      .post('/asistencia/check-in')
      .set('Authorization', `Bearer ${tokenS1}`)
      .send({
        operarioId: o1Id,
        date: '2026-06-01',
        checkInCapturedAt: new Date().toISOString(),
        checkInLat: 7.5,
        checkInLng: -76.5,
        clientRef: `delta-test-${Date.now()}`,
      });
    expect(checkInRes.status).toBe(201);
    const attId = checkInRes.body.id;
    const attClientRef = checkInRes.body.clientRef;

    // Capture actual updatedAt from the created record
    const attRecord = await prisma.attendance.findUnique({ where: { id: attId } });
    expect(attRecord).toBeTruthy();

    // Since before check-in ÔåÆ attendance should appear
    const res = await request(app.getHttpServer())
      .get(`/asistencia?since=${encodeURIComponent(cursor)}`)
      .set('Authorization', `Bearer ${tokenS1}`);
    expect(res.status).toBe(200);
    const ids = res.body.map((a: any) => a.id);
    expect(ids).toContain(attId);

    // SD-14: ?clientRef= recovery ÔÇö returns the same record
    const clientRefRes = await request(app.getHttpServer())
      .get(`/asistencia?clientRef=${encodeURIComponent(attClientRef)}`)
      .set('Authorization', `Bearer ${tokenS1}`);
    expect(clientRefRes.status).toBe(200);
    expect(Array.isArray(clientRefRes.body)).toBe(true);
    expect(clientRefRes.body.length).toBe(1);
    expect(clientRefRes.body[0].id).toBe(attId);

    // SD-15: ?clientRef= with non-existent ref ÔåÆ 200 []
    const notFoundRes = await request(app.getHttpServer())
      .get(`/asistencia?clientRef=nonexistent-ref-xyz`)
      .set('Authorization', `Bearer ${tokenS1}`);
    expect(notFoundRes.status).toBe(200);
    expect(notFoundRes.body).toEqual([]);
  });

  // ÔöÇÔöÇÔöÇ SD-16: scope enforcement on attendance delta ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SD-16: GET /asistencia?since= scope-enforced (S2 cannot see S1 attendance)', async () => {
    const cursor = new Date(Date.now() - 10_000).toISOString();
    const res = await request(app.getHttpServer())
      .get(`/asistencia?since=${encodeURIComponent(cursor)}`)
      .set('Authorization', `Bearer ${tokenS2}`);
    expect(res.status).toBe(200);
    // S2 should not see any attendance created by S1
    const body = res.body as Array<{ supervisorId: string }>;
    for (const att of body) {
      expect(att.supervisorId).toBe(s2Id);
    }
  });

  // ÔöÇÔöÇÔöÇ SD-17: ?clientRef= cross-tenant isolation ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SD-17: ?clientRef= cross-tenant ÔÇö S2 cannot see S1 clientRef ÔåÆ 200 []', async () => {
    // Create S1 attendance and try to fetch it as S2
    const s1CheckIn = await request(app.getHttpServer())
      .post('/asistencia/check-in')
      .set('Authorization', `Bearer ${tokenS1}`)
      .send({
        operarioId: o1Id,
        date: '2026-06-02',
        checkInCapturedAt: new Date().toISOString(),
        checkInLat: 7.5,
        checkInLng: -76.5,
        clientRef: `cross-tenant-ref-${Date.now()}`,
      });
    expect(s1CheckIn.status).toBe(201);
    const s1ClientRef = s1CheckIn.body.clientRef;

    // S2 tries to retrieve S1's attendance by clientRef ÔåÆ 200 [] (fail-closed)
    const res = await request(app.getHttpServer())
      .get(`/asistencia?clientRef=${encodeURIComponent(s1ClientRef)}`)
      .set('Authorization', `Bearer ${tokenS2}`);
    expect(res.status).toBe(200);
    expect(res.body).toEqual([]);
  });

  // ÔöÇÔöÇÔöÇ SD-18..SD-21: novedad delta filter ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SD-18: GET /novedades?since= future ÔåÆ empty', async () => {
    const future = new Date(Date.now() + 60_000).toISOString();
    const res = await request(app.getHttpServer())
      .get(`/novedades?since=${encodeURIComponent(future)}`)
      .set('Authorization', `Bearer ${tokenS1}`);
    expect(res.status).toBe(200);
    expect(res.body).toEqual([]);
  });

  it('SD-19: GET /novedades?since= cursor before novedad creation ÔåÆ returns novedad', async () => {
    const cursor = new Date(Date.now() - 500).toISOString();

    // Need a COMPLETED attendance to create a novedad.
    // First check-in via API
    const checkInRes = await request(app.getHttpServer())
      .post('/asistencia/check-in')
      .set('Authorization', `Bearer ${tokenS1}`)
      .send({
        operarioId: o1Id,
        date: '2026-06-03',
        checkInCapturedAt: new Date().toISOString(),
        checkInLat: 7.5,
        checkInLng: -76.5,
        clientRef: `novedad-delta-ref-${Date.now()}`,
      });
    expect(checkInRes.status).toBe(201);
    const attId = checkInRes.body.id;

    // Set signatureKey directly (bypass upload) and complete the record via direct DB update
    // so checkout doesn't require a real file upload in this test.
    await prisma.attendance.update({
      where: { id: attId },
      data: { signatureKey: 'test-sig-key', completedAt: new Date() },
    });

    // Create novedad (requires completedAt != null)
    const novRes = await request(app.getHttpServer())
      .post(`/asistencia/${attId}/novedades`)
      .set('Authorization', `Bearer ${tokenS1}`)
      .send({ horasExtra: '2.00', motivo: 'delta test' });
    expect(novRes.status).toBe(201);
    const novId = novRes.body.id;

    // Fetch delta ÔåÆ should include novedad
    const res = await request(app.getHttpServer())
      .get(`/novedades?since=${encodeURIComponent(cursor)}`)
      .set('Authorization', `Bearer ${tokenS1}`);
    expect(res.status).toBe(200);
    const ids = res.body.map((n: any) => n.id);
    expect(ids).toContain(novId);
  });

  // ÔöÇÔöÇÔöÇ SD-20: novedad delta scope enforcement ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SD-20: GET /novedades?since= scope-enforced (S2 cannot see S1 novedades)', async () => {
    const cursor = new Date(Date.now() - 30_000).toISOString();
    const res = await request(app.getHttpServer())
      .get(`/novedades?since=${encodeURIComponent(cursor)}`)
      .set('Authorization', `Bearer ${tokenS2}`);
    expect(res.status).toBe(200);
    // S2 should only see its own novedades (none in this suite)
    const body = res.body as Array<{ supervisorId: string }>;
    for (const nov of body) {
      expect(nov.supervisorId).toBe(s2Id);
    }
  });

  // ÔöÇÔöÇÔöÇ SD-21: inclusive cursor (boundary row included) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SD-21: ?since= cursor is INCLUSIVE (boundary row returned)', async () => {
    // Get O1 current updatedAt and use that exact timestamp as cursor
    const o1Row = await prisma.operario.findUnique({ where: { id: o1Id } });
    expect(o1Row).toBeTruthy();
    const boundaryTs = o1Row!.updatedAt.toISOString();

    const res = await request(app.getHttpServer())
      .get(`/iam/operarios?since=${encodeURIComponent(boundaryTs)}`)
      .set('Authorization', `Bearer ${tokenAdmin}`);
    expect(res.status).toBe(200);
    const ids = res.body.map((o: any) => o.id);
    // O1 updatedAt === boundary ÔåÆ inclusive, MUST be included
    expect(ids).toContain(o1Id);
  });

  // ÔöÇÔöÇÔöÇ SD-22: operario response includes updatedAt field ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SD-22: GET /iam/operarios response rows include updatedAt', async () => {
    const res = await request(app.getHttpServer())
      .get('/iam/operarios')
      .set('Authorization', `Bearer ${tokenAdmin}`);
    expect(res.status).toBe(200);
    for (const op of res.body as Array<{ updatedAt?: unknown }>) {
      expect(op.updatedAt).toBeDefined();
    }
  });

  // ÔöÇÔöÇÔöÇ SD-23: attendance ?since= and ?clientRef= mutually exclusive ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SD-23: ?clientRef= takes precedence ÔÇö when both provided, clientRef is used', async () => {
    // Create an attendance for S1
    const checkInRes = await request(app.getHttpServer())
      .post('/asistencia/check-in')
      .set('Authorization', `Bearer ${tokenS1}`)
      .send({
        operarioId: o1Id,
        date: '2026-06-10',
        checkInCapturedAt: new Date().toISOString(),
        checkInLat: 7.5,
        checkInLng: -76.5,
        clientRef: `precedence-ref-${Date.now()}`,
      });
    expect(checkInRes.status).toBe(201);
    const attClientRef = checkInRes.body.clientRef;

    // Send both ?since= and ?clientRef= ÔÇö clientRef takes precedence
    const res = await request(app.getHttpServer())
      .get(`/asistencia?since=${encodeURIComponent(new Date(0).toISOString())}&clientRef=${encodeURIComponent(attClientRef)}`)
      .set('Authorization', `Bearer ${tokenS1}`);
    expect(res.status).toBe(200);
    expect(Array.isArray(res.body)).toBe(true);
    // clientRef branch returns exactly [record] or []
    expect(res.body.length).toBe(1);
    expect(res.body[0].clientRef).toBe(attClientRef);
  });

  // ÔöÇÔöÇÔöÇ SD-24: operario scope enforcement on delta mode ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  it('SD-24: GET /iam/operarios?since= scope-enforced (S1 cannot see S2 operarios)', async () => {
    // Reactivate O2 for this test (was deactivated in SD-10)
    await prisma.operario.update({ where: { id: o2Id }, data: { deactivatedAt: null } });

    const cursor = new Date(Date.now() - 10_000).toISOString();
    const res = await request(app.getHttpServer())
      .get(`/iam/operarios?since=${encodeURIComponent(cursor)}`)
      .set('Authorization', `Bearer ${tokenS1}`);
    expect(res.status).toBe(200);
    // S1 sees only their scope ÔÇö O2 (under S2) excluded
    const ids = res.body.map((o: any) => o.id);
    expect(ids).not.toContain(o2Id);
  });
});

/**
 * Zone & Municipio CRUD Integration Suite.
 *
 * Covers the 6 new write endpoints added in WU-zones-municipios-crud:
 *
 * ZONES:
 *   ZC-01  POST /org/zones ÔÇö happy path (SYSTEM_ADMIN) ÔåÆ 201 {id}
 *   ZC-02  POST /org/zones ÔÇö duplicate name ÔåÆ 409
 *   ZC-03  POST /org/zones ÔÇö GERENCIA caller ÔåÆ 403
 *   ZC-04  POST /org/zones ÔÇö no token ÔåÆ 401
 *   ZC-05  PATCH /org/zones/:id ÔÇö rename happy path ÔåÆ 200 ZoneResponseDto
 *   ZC-06  PATCH /org/zones/:id ÔÇö not found ÔåÆ 404
 *   ZC-07  PATCH /org/zones/:id ÔÇö name collides with existing zone ÔåÆ 409
 *   ZC-08  DELETE /org/zones/:id ÔÇö happy path (no dependents) ÔåÆ 200
 *   ZC-09  DELETE /org/zones/:id ÔÇö not found ÔåÆ 404
 *   ZC-10  DELETE /org/zones/:id ÔÇö has municipios ÔåÆ 409
 *   ZC-11  DELETE /org/zones/:id ÔÇö has supervisors ÔåÆ 409
 *   ZC-12  DELETE /org/zones/:id ÔÇö has coordinador ÔåÆ 409
 *   ZC-13  PATCH /org/zones/:id ÔÇö TALENTO_HUMANO caller ÔåÆ 200 (in ORG_WRITE_ROLES)
 *
 * MUNICIPIOS:
 *   MC-01  POST /org/municipios ÔÇö happy path ÔåÆ 201 {id}
 *   MC-02  POST /org/municipios ÔÇö duplicate (zoneId,name) ÔåÆ 409
 *   MC-03  POST /org/municipios ÔÇö unknown zoneId ÔåÆ 400
 *   MC-04  POST /org/municipios ÔÇö GERENCIA caller ÔåÆ 403
 *   MC-05  PATCH /org/municipios/:id ÔÇö rename happy path ÔåÆ 200 MunicipioResponseDto
 *   MC-06  PATCH /org/municipios/:id ÔÇö move to different zone ÔåÆ 200
 *   MC-07  PATCH /org/municipios/:id ÔÇö not found ÔåÆ 404
 *   MC-08  PATCH /org/municipios/:id ÔÇö (zoneId,name) collision ÔåÆ 409
 *   MC-09  PATCH /org/municipios/:id ÔÇö new zoneId not found ÔåÆ 400
 *   MC-10  DELETE /org/municipios/:id ÔÇö happy path (no supervisors) ÔåÆ 200
 *   MC-11  DELETE /org/municipios/:id ÔÇö not found ÔåÆ 404
 *   MC-12  DELETE /org/municipios/:id ÔÇö has supervisors ÔåÆ 409
 *
 * Setup strategy:
 *   - Bootstrap AppModule with mock StoragePort (same pattern as operario-management.int-spec.ts)
 *   - Create a SYSTEM_ADMIN + TALENTO_HUMANO + GERENCIA user with DeviceSessions for auth
 *   - Zones/municipios created per-test and cleaned up per-test / afterAll
 *   - Seeded zones (Zona Urab├í, Zona Bajo Cauca) are used for collision and dependents tests
 *   - Teardown is FK-safe
 */

